(window.courseContentFiles = window.courseContentFiles || {})["000003/0003"] = "<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Колоквиум 4. Полови системи и новородено.</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0; \n    }\n    ul, ol { \n      margin: 0.2em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^(?:---|\\*\\*\\*|___)$/.test(content)) {\n              html.push('<hr>');\n            } else if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<h1 style=\"text-align: center\">Клинични задачи</h1><blockquote>По-добре от сайта в blackboard, защото има по-малък шанс за грешки + има обяснения.</blockquote><p><strong>1.</strong> 36 годишна жена се оплаква от епизодични болки ниско в корема и таза от около 10 г. Гинекологичният преглед и ехографското изследване на тазовите органи не откриват промени. РАР тестът е негативен. Прибягва се до лапароскопия и лекуващият лекар забелязва няколко малки (0, 2 до 0, 5 см) синьо-червени нодуларни лезии по серозната повърхност на матката, тръбите и апендикса. Лезиите са ексцизирани и микроскопското изследване показва наличие на ендометриални жлези и строма. Кое от долните твърдения, касаещи заболяването на жената, е най-вероятно:</p><ul><li><strong>Може да предизвика диспареуния</strong></li><li>Затлъстяването е рисков фактор</li><li>Може да възникне на базата на метаплазия на перитонеалния мезотел</li><li>С развитието на заболяването менструацията спира</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>2.</strong> 47 годишна жена съобщава за чувствителност при натиск, но без болка ниско в корема от няколко месеца. Ехографското изследване показва 10 см кистична маса в областта на левия яйчник. Чрез ТАБ се взема течност за цитологично изследване, която е бистра, но се откриват групи туморни клетки, заобикалящи псамомни телца. Пациентката най-вероятно има:</p><ul><li><strong>Серозен цистаденокарцином на яйчника</strong></li><li>Аденокарцином на маточната тръба</li><li>Мезотелиом</li><li>Зрял кистичен тератом на яйчника</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>3.</strong> 30 годишна жена с инфертилитет се оплаква от епизодични болки ниско в корема от няколко години. Физикалното и гинекологично изследване не установяват туморни маси в малкия таз. РАР тестът установява само малко на брой трихомони и липса на диспластични клетки. Направена е лапароскопия и гинекологът забелязва малки синьочервени леко надигнати лезии с диаметър 0,2 и 0,4 см по перитонеума, широките лигаменти и Дъгласовото пространство. Тези лезии представляват най-вероятно:</p><ul><li><strong>Ендометриоза</strong></li><li>Метастатичен аденокарцином</li><li>Инфикция с Neisseria gonorrheae</li><li>Кандидоза</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>4.</strong> 43 годишна жена съобщава, че от няколко месеца менструалните й течения са станали по обилни и траят по 6-8 дни. Забелязала и епизодични кръвотечения извън цикъла. При гинекологичния прегледа шийката на матката изглежда нормална и РАР тестът не открива абнормни клетки. Гинекологичното изследване установява матка с нодуларност и двойно увеличени размери. Ехографията на надбъбреците не показва патологични промени. Най вероятно се касае за:</p><ul><li><strong>Миоматозна матка</strong></li><li>Ендометриален карцином</li><li>Ектопична бременност</li><li>Първичен сифилис</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>5.</strong> 50 годишна жена забелязала увеличаващи се размери на корема от една година. Физикалното изследване установява свободна течност в коремната кухина, без болезненост, нормална перисталтика. Няма генитално кървене. Ехографското изследване открива аднексиални маси с размери 10 и 7 см. По време на операцията установявате двустранно еднокамерни кисти, изпълнени с бистро съдържимо и папиларни, подобни на цветно зеле, образувания по външната и вътрешната им повърхност. Тези двустранни маси най-вероятно са:</p><ul><li><strong>Билатерален серозен кистаднокарцином</strong></li><li>Гранулозо-клетъчни тумори</li><li>Зрели кистични тератоми</li><li>Фибросаркома с метастази</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>6.</strong> При проведен РАР тест на здрава, сексуално активна 28 годишна жена се откриват цитологични белези за висока степен сквамозна интраепителна лезия (SIL),(респективно PAP IV). Гинекологичният преглед не открива патологични промени. Тази лезия най вероятно е във връзка със:</p><ul><li><strong>Human papillomavirus</strong></li><li>Herpes simplex virus инфекция</li><li>Epstein-Barr virus</li><li>Trichomonas vaginalis</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>7.</strong> 23 годишна жена е приета в болницата с отпадналост и обърканост от 1 ден, трудно контактна. Тестът за бременност е позитивен. Лабораторните изследвания показват констелация, характерна за ДИК (дисеминирано интравазално кръвосъсирване) синдром. Състоянието на пациентката може да се обясни с всички изброени проблеми на бременността, с изключение на:</p><ul><li><strong>Инфаркт на плацентата</strong></li><li>Амниотична емболия</li><li>Еклампсия</li><li>Задържан мъртъв плод</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>8.</strong> 22 годишна жена изхвърля през вагината гроздовидни маси през 16 седмица на първата си бременност. Не е усещала движения на плода до това време. Направен е кюретаж - от маточната кухина се изваждат около 1000 сс същите гроздовидни маси, представляващи пълни с течност везикули, с размери до 1,5 см. Кой от изброените методи е най-удачен за проследяване състоянието на жената:</p><ul><li><strong>Серумен хорионгонадотропен хормон (ХГХ)</strong></li><li>Рентгенография на белия дроб</li><li>Ехографско изследване на тазовите органи</li><li>Pap тест</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>9.</strong> 23 годишна жена е приета в спешен център поради внезапна болка ниско в корема. Гинекологичното изследване установява нормална по размери матка, цервикс и вагина и болезненост при палпация в областта на левите аднекси. Трансвагиналната ехография не установява интраутеринен гестационен сак, но се вижда туморовидна маса с диаметър 2 см в областта на левите аднекси. Кулдоскопията установява наличие на кръв в Дъгласовото пространство. Кое е най-подходящото следващо изследване на този етап:</p><ul><li><strong>Изследване на хорионгонадотропен хормон</strong></li><li>Рар тест</li><li>Рутинно изследване на урина</li><li>Ендометриална биопсия</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>10.</strong> Коя е най-вероятната причина за хемотоколпос при 14 годишно момиче?</p><ul><li><strong>Неперфориран химен</strong></li><li>Цервикален кондилом</li><li>Руптурирала Бартолинова жлеза</li><li>Цервикална гонорея</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>11.</strong> 50 годишна жена е забелязала, че през последната 1 година менструалните й кръвотечения са по-обилни и продължителни, средно 7-9 дни. Съобщава и за епизодични метрорагии. През последните 3 месеца е приемала желязосъдържащи препарати за коригиране на анемичен синдром. При гинекологичния преглед цервиксът е непроменен, но матката е с двойно увеличени размери. Трансвагиналната ехография установява наличието на 9 см плътна туморна маса в матката. Направена е хистеректомия. Описаният тумор макроскопски е с вид на рибе месо. Микроскопски, туморът е много целуларен, с вретеновидни клетки, с хиперхромни ядра и 10-20 митози на поле при силно увеличение. Най-вероятната диагноза е:</p><ul><li><strong>Лейомиосарком</strong></li><li>Ендометриален полип</li><li>Аденомиоза</li><li>Ектопична бременност</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>12.</strong> Нарушена бременност (изразено кървене във втория триместър) при 31 годишна жена налага извършването на кюретаж. Две седмици след манипулацията кървенето продължава (макар и намаляло) и нивата на хорионгонадропния хормон остават високи. Кое от изброените е най-вероятно да настъпи:</p><ul><li><strong>Хориални въси, инвазиращи миометриума</strong></li><li>Поява на хеморагични маси в белите дробове</li><li>Спонтанно излекуване</li><li>Установяване на кариотип 46 XY на интраутеринното съдържимо</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>13.</strong> 33 годишна жена и нейният съпруг искат дете, но тя не може да зачене. Сперматограмата на съпруга е нормална. Кое от изброените е НАЙ-МАЛКО ВЕРОЯТНАТА причина за инфертилитета.</p><ul><li><strong>Хроничен цервицит</strong></li><li>Лайдиг-клетъчен тумор</li><li>Пролактином</li><li>Хроничен салпингит/салпингооофорит (Pelvic inflammatory disease)</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>14.</strong> 19 годишна жена има няколко сиворозови окръглени, леко надигнати (подобни на брадавици) лезии с диаметър 1-2 см по перинеума и вулвата. Биопсията на една от лезиите показва папиларни разраствания, тапицирани с акантотично задебелен и с койлоцитна трансформация многослоен плосък епител. Кое от изброените твърдения е най-вероятно:</p><ul><li><strong>Може да настъпи прогресия до плоскоклетъчен карцином</strong></li><li>Подобни лезии се срещат често и преди пубертета</li><li>Повечето се откриват в ендометриума</li><li>Имат връзка с кандида инфекция</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>15.</strong> При 32 годишна жена, бременна в 18 гестационна седмица, детските сърдечни тонове не се долавят. Ехографското изследване не открива фетус, а само множество ехогенни кисти, изпълващи кухината на матката. Кой от изброените процеси е най-вероятен:</p><ul><li><strong>Комплетна мола хидатидоза</strong></li><li>Инвазивна мола хидатидоза</li><li>Парциална мола хидатидоза</li><li>Хорионкарцином</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>16.</strong> Поради абнормен Рар тест е направена цервикална биопсия на 38 годишна жена. Биопсията показва дисплазия, ангажираща цялата дебелина на цервикалния епител. Вашата диагноза е:</p><ul><li><strong>Цервикална интраепителна неоплазия III (CIN III)</strong></li><li>Хроничен обострен цирвицит, свързан със Herpes simplex вирусна инфекция</li><li>Ендоцервикален аденокарцином</li><li>Екстрамамарна болест на Пейджет</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>17.</strong> 25 годишна жена има тъмнокафяво, неприятно миришещо течение от влагалището, започнало 2 седмици след раждането на доносено здраво дете. Има температура. При гинекологичното изследване се установява леко уголемена матка и болезненост при палпация. Нивото на Хорионгонатропният хормон в кръвта е нормално. Кое от изброените състояния е най-вероятно:</p><ul><li><strong>Задържани плацентарни части</strong></li><li>Инвазивна мола</li><li>Дегенериращ лейомиом</li><li>Синдром на Шийхан</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>18.</strong> 39 годишна жена има дисменорея от няколко месеца. Рар тестът и тестът за бременност са негативни. При гинекологичното изследване не се установяват туморни маси в аднексите. Цервиксът е нормален. Матката е дифузно увеличена с размери три пъти над нормата, без туморни формации и с почти нормална по размери кухина. Направена е тотална хистеректомия. Каква микроскопска находка е най-вероятно да бъде установена:</p><ul><li><p><strong>Хиперхромни и плейоморфни гладкомускулни клетки с изразена митотична активност</strong></p><br></li><li>Ендометриални жлези и строма в миометриума</li><li>Атипични жлези, инвазиращи стената на матката</li><li>Големи, аваскуларни хориални въси с трофобластна пролиферация</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>19.</strong> При преглед на 22 годишна жена се установяват няколко сиворозови, леко надигнати лезии с неравна повърхност и размери 0,5-1 см в областта на перинеума. Една от тях е изследвана микроскопски и се установява папиларно разрастване, тапицирано с многослоен плосък епител и койлоцитни промени. Какво е значението на тези лезии:</p><ul><li><strong>Може да има прогресия до in situ и инвазивен карцином</strong></li><li>Жената трябва да бъде лекувана за гонококова инфекция</li><li>Трябва да се търси подлежаща малигненост</li><li>Лезиите са белези на синдрома на Търнър</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>20.</strong> 55 годишна жена се оплаква от болки ниско в корема. Преди 25 години е направена обикновена хистеректомия. При ехографското и лапароскопско изследване в областта на левия яйчник се установява туморна маса с диаметър 9 см. Хистологично се откриват полиморфни туморни жлези, напомнящи ендометриалните. Какъв патологичен процес е имало в премахнатата преди 25 години матка?</p><ul><li><strong>Ендометриоза по серозната повърхност на матката, тръбите и лигаментите</strong></li><li>Аденомиоза</li><li>Хроничен ендометрит</li><li>Ендометриална хиперплазия</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>21.</strong> 38 годишна жена се оплаква от бяло, като „пресечено мляко“ вагинално течение от няколко седмици. Не съобщава за извънменструално кървене. Рар тестът показва нормален плосък епител, единични левкоцити и псевдохифи. Кой от изброените инфикциозни агенти най-вероятния причинител:</p><ul><li><strong>Candida albicans</strong></li><li>Treponema pallidum</li><li>Herpes simplex</li><li>Escherichia coli</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>22.</strong> 35 годишна жена се оплаква от тъпи болки ниско в корема от няколко месеца. Гинекологичното изследване установява нормален цервикс и матка, а в левия аднекс се палпира голяма и болезнена при палпация туморна маса. Ехографски се открива 8 см кистична маса в левия яйчник, изпълнена с течност. По време на лапаротомията се установяват множество нишковидни сраствания в малкия таз. Овариалният тумор е изрязан и изследван в Центъра по патология. Макроскопски се установява кистична формация, изпълнена с гноевиден ексудат. Микроскопски в стената на кистата се откриват остатъци от маточна тръба и яйчник. Кой от изброените инфекциозни агенти най-вероятно е довел до тази находка:</p><ul><li><strong>Neisseria gonorrheae</strong></li><li>Human papillomavirus</li><li>Mycobacterium tuberculosis</li><li>Trichomonas vaginalis</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>23.</strong> Поради маточни кръвотечения от няколко месеца, жена на 62 години посетила личния си лекар. Жената никога не е забременявала и от 15 години е в менопауза. Личният й лекар я насочва към гинеколог, който извършва ендометриална биопсия. Морфологичният отговор е добре диференциран ендометриален карцином. При тази ситуация, ако се открие яйчников тумор, той най-вероятно ще бъде:</p><ul><li><strong>Гранулозоклетъчен тумор</strong></li><li>Папиларен серозен кистазнокарцином</li><li>Крукенбертов тумор</li><li>Незрял тератом</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>24.</strong> 56 годишна бездетна жена е в менопауза от 9 години. Съобщава за маточно кървене в последните седмици. Кой от изброените диагностични методи е най-подходящ:</p><ul><li><strong>Ендометриална биопсия</strong></li><li>Рар тест</li><li>Компютър томографско изследване на малкия таз</li><li>Колпоскопия</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>25.</strong> 50 годишна жена съобщава за дискомфорт ниско в корема от няколко месеца. Направеното КТ изследване установява лобулирани кистични билатерални лезии в областта на яйчниците с размери 10 и 8 см. Коя от изброените неоплазми е най-вероятна:</p><ul><li><strong>Серозен кистаденокарцином</strong></li><li>Зрял кистичен тератом</li><li>Фибротеком</li><li>Муцинозен цистаденом</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>26.</strong> 48 годишна жена забелязва оскъдно кървене извън менструалните цикли през последните 2 месеца. Гинекологичното изследване не открива цервикални лезии и Рар тестът е отрицателен. Извършена е ендометриална биопсия с отговор - жлезиста хиперплазия на ендометриума. Ехографското изследване установява туморна маса в левия яйчник. Най вероятно това е:</p><ul><li><strong>Фибротекома</strong></li><li>Зрял кистичен тератом</li><li>Крукенбергов тумор</li><li>Сертоли-Лайдигов тумор</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>27.</strong> От известно време 35 годишна жена е с неясни оплаквания от лесна умора и общ дискомфорт. Установявате субфебрилна температура, ингвинална лимфаденопатия и дифузен обрив по тялото. Кожната биопсия открива дифузни периваскуларни инфилтрати от плазматични клетки. Кой от изброените инфекциозни причинители е най-вероятно отговорен за оплакванията на жената:</p><ul><li><strong>Treponema pallidum</strong></li><li>Herpes simplex</li><li>Candida albicans</li><li>Neisseria gonrrheae</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>28.</strong> Ехографски е установена туморна маса в десния яйчник на 40 годишна жена. При лапаротомията се намира кистичен тумор, прикрепен към яйчника. Повърхността на кистата е с макроскопски видими папиларни разраствания. Кой критерий е най-сигурен при разграничаването на \"граничен серозен тумор\" от серозен цистаденокарцином:</p><ul><li><strong>Инвазия на овариалната строма</strong></li><li>Ангажирането и на другия яйчник</li><li>Наличието на псамомни телца</li><li>Клетъчна атипия</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>29.</strong> Получавате хистологичен отговор на кюретажен материал: „Ендометриални жлези в пролиферативна фаза и морфологични данни за хроничен ендометрит“. Ще го интерпретирате като:</p><ul><li><strong>Промени, предизвикани от интраутеринна спирала</strong></li><li>Премалигнена ендометриална лезия</li><li>Хиперестрогенно състояние</li><li>Синдром на Щайн-Льовентал</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>30.</strong> 19-годишна примагравида (бременна за първи път жена) получава кървене от гениталиите и коликообразни болки ниско в корема в 12 гестационна седмица. До момента бременността е била неусложнена. Абортира спонтанно. Кой от изброените процеси е най вероятното обяснение за аборта.</p><ul><li><strong>Хромозомна аномалия</strong></li><li>Плацентарна инсуфициенция</li><li>Вродена инфекция</li><li>Токсемия на бременността</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>31.</strong> 19-годишна жена, втора бременност, второ раждане. Първата бременност завършва с нормално раждане на доносен плод в дома. Настоящата бременност завършва с раждане на бебе с тегло 2990 гр в 35 гестационна седмица. Бебето е оточно и иктерично. Не се установяват вродени аномалии. Хемоглобинът на бебето е 8,5 g/dl. Плацентата също е оточна, но няма възпаление на плацентарните вили или на феталните мембрани. Кое от изброените е най-вероятното обяснение за състоянието на бебето:</p><ul><li><strong>Преминаване на антитела на майката през плацентата</strong></li><li>Заразяване на майката с рубеола през първия триместър</li><li>Хромозомни аномалии на майката</li><li>Повишени нива на глюкозата в кръвта на майката</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>32.</strong> 25-годишта жена, 3-та бременност във 39 гестационна седмица. Две нормални предшестващи раждания. От 25 дни не усеща движения на плода. Преди това бременността не е имала усложнения. След разкъсване на околоплодния мехур се ражда мъртъв плод. Микроскопското изследване на околоплодния мехур установява изразен остър хориоамниит. Кой от изброените инфекциозни причинители е отговорен за вътреутробната смърт на плода:</p><ul><li><strong>Хемолитичен стрептокок от група В</strong></li><li>Токсоплазма гондии</li><li>Херпес симплекс вирус</li><li>Трепонема палидум</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>33.</strong> Бебе, родено през 38 гестационна седмица, тежи 2270 гр. Бременността е протекла без усложнения. Не се откриват видими малформации при огледа на детето после раждането, но то изглежда диспропорционално - размерът на главата съответства на гестационната възраст повече, отколкото размера на тялото. Кое от изброените може да обясни находката:</p><ul><li><strong>Тютюнопушене през време на бременността</strong></li><li>Тризомия 18</li><li>Болест на Ниман-Пик</li><li>Диабет на майката</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>34.</strong> Майка забелязва, че 18-месечното й бебе не наддава на тегло през последните 2-3 месеца. Коремът на детето изглежда по-голям от обичайното за възрастта. Физикалното изследване установява обемна маса в горния ляв квадрант на корема. Най-вероятната диагноза е:</p><ul><li><strong>Невробластом</strong></li><li>Рецесивна поликистична болест на бъбреците</li><li>Кистична фиброза (муковисцидоза)</li><li>Кистичен хигром</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>35.</strong> Кое от изброените най-добре ни помага да различим \"аборт\" от \"мъртвородено\"</p><ul><li><strong>Възрастта или теглото на плода</strong></li><li>Липсата на вродени малформации</li><li>Мацерация на плода</li><li>Наличието на инфекция</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>36.</strong> Скоро след раждането се установява респираторен-дисстрес синдром при бебе, родено в 32 гестационна седмица. Бебето тежи 3550 гр. Не се установяват вродени малформации при огледа. Медикаментозно се овладява епизод на хипогликемия. Кой от изброените пренатални тестове на майката предполага тази находка:</p><ul><li><strong>Повишен серумен хемоглобин А1С</strong></li><li>Повишен хорионгонадотропен хормон</li><li>Полихидрамнион, установен ехографски</li><li>Кариотип 47, XYY при амниоцентеза</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>37.</strong> След раждане в 36 гестационна седмица в плацентата се откриват множество полиморфонуклеарни левкоцити по феталните мембрани (хориона и амниона). Това най често се среща при:</p><ul><li><strong>Преждевременно пукване на околоплодния мехур</strong></li><li>Herpes simplex инфекция на плода</li><li>Многоплодна бременност</li><li>Abruptio placenta</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>38.</strong> Бременна жена се тревожи, че може да роди дете със синдрома на Даун. Каква процедура бихте назначили в пренаталния период, за да разберете дали фетусът има синдрома на Даун:</p><ul><li><strong>Амниоцентеза</strong></li><li>Ехографско изследване</li><li>Изследване на алфа-фетопротеина на майката</li><li>Изследване на кръвната група на майката</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>39.</strong> 10. Раждане в 31 гестационна седмица. Новороденото развива респираторен дисстрес и загива въпреки интубацията и механичната вентилация. След аутопсия микроскопски в белите дробове се откриват множество розови хиалинни мембрани в алвеолите и алвеоларните ходове на белите дробове. Кое от изброените състояния е допринесло най много за това:</p><ul><li><strong>Липса на сърфактант</strong></li><li>Тризомия 16</li><li>Пъпна връв с два съда (артерия и вена)</li><li>Диабет на майката</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>40.</strong> Раждане в термин. Забелязвате, че плодната часть на плацентата, която е с нормална големина, е зеленикаво оцветена. Тази находка е съвместима със:</p><ul><li><strong>Мекониално оцветяване</strong></li><li>Плацента превия</li><li>Абрупцио на плацентата</li><li>Хориоамнионит</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>41.</strong> Ехографското изследване в 16 гестационна седмица на 21-годишна жена установява силно повишено количество амниотична течност (полихидрамнион). Най-вероятно това е резултат от кои аномалии на плода:</p><ul><li><strong>Атрезия на дебело черво.</strong></li><li>Агенезия на бъбреците</li><li>Дефект на междукамерната преграда</li><li>Цитомеголовирусна инфекция</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>42.</strong> Забелязвате подуване на корема през първата седмица от живота на дете, родено в термин. Диагностицирате мекониум илеус и насочвате детето за спешна операция. В следоперативния период детето е с персистираща стеаторея и не наддава на тегло. Кой от изброените лабораторни резултати вероятно е свързан със заболяването на детето:</p><ul><li><strong>Повишени хлориди при потен тест</strong></li><li>HIV +</li><li>Хипербилирубиемия</li><li>Повишени нива на хомованиловата киселина в урината</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>43.</strong> Коя от изброените находки е обичайна за пъпната връв на доносено бебе от неусложнена първа бременност на 23-годишна жена:</p><ul><li><strong>Изхождане на пъпната връв малко встрани от центъра на плацентата</strong></li><li>Дължина 90 см</li><li>Една артерия и една вена</li><li>Единичен възел по средата на пъпната връв</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>44.</strong> 20-годишна жена с неусложнена бременност не е посещавала личния си лекар по време на бременността. Започва нормално раждане в 38 гестационна седмица, но неочаквано се появява масивно вагинално кръвотечение. Най-вероятното обяснение за това е:</p><ul><li><strong>Плацента превия</strong></li><li>Пролапс на пъпната връв</li><li>Инфаркт на плацентата</li><li>Хориоамниит</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>45.</strong> При дете от доносена бременност в неонаталният период се развива на мекониум илеус. На 11 годишна възраст са установени повишени хлориди при потен тест. През детството имало множество все по-тежки пневмонии с продуктивна кашлица, като най-често е изолиран Pseudomonas aeruginosa. Въз основа на тази находка има риск детето в по нататъшния си живот да развие:</p><ul><li><strong>Бронхиектазии</strong></li><li>Плеврални плаки</li><li>Лимфангиектазии</li><li>Пневмоцистна пневмония</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>46.</strong> 70-годишна жена с болест на Алцхаймер е с постоянни грижи в старчески дом. Жената няма двигателен дефицит, но е летаргична и прекарва дните си в леглото. Тя развива остро фебрилно заболяване с увеличаваща се експекторация на жълтеникави храчки. Рентгеновата графия показва инфилтрати, които почти изцяло засенчват долния дял на левия бял дроб. Четири дни по-късно жената загива. При аутопсията се открива почти изцяло консолидиран ляв долен лоб, със сивкав цвят и дребнозърнеста повърхност и нежен белезникав налеп по плеврата. Най-вероятният инфекциозен причинител е:</p><ul><li><strong>Streptococcus pneumoniae</strong></li><li>Listeria monocytogenes</li><li>Cryptococcus neoformans</li><li>Mycobacterium tuberculosis</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>47.</strong> 9-годишно момиче се оплаква от затруднено дишане от около седмица. Детето е субфебрилно (37,9 С). Рентгенографията открива изразена хилусна лимфаденопатия и периферен възел в средния дял на десния бял дроб с диаметър 1 см. Липсват инфилтративни засенчвания в белите дробове. Рутинното микробиологично изследване нe установява патогенна флора. Кое от изброените състояния е най-вероятно:</p><ul><li><strong>Инфекция с микобактериум туберкулозе</strong></li><li>Алергичен (хиперсенситивен) пневмонит</li><li>Белодробен карциноид</li><li>Инфекциозен ендокардит</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>48.</strong> До 11-я следоперативен ден след простатектомия по повод аденокарцином на простатната жлеза 70-годишен мъж се възстановява без проблеми. Той отива самостоятелно до банята, но при връщане в леглото внезапно получава остра диспнея, изпотяване, палпитации, съпроводени със силен страх. Кое от изброените ще подозирате като причина за това състояние:</p><ul><li><strong>Белодробен ембол</strong></li><li>Белодробен оток</li><li>Плеврален излив</li><li>Постоперативни ателектази</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>49.</strong> 50-годишна жена, работила цял живот като шивачка, се оплаква от недостиг на въздух, загуба на тегло, повишена температура, нощни изпотявания от няколко месеца. Рентгенографията на белия дроб открива увеличени лимфни възли в хилуса и ретикулонодуларни промени в белодробните основи. Кожните проби за заушка и антигени на Candidа spеcies са отрицателни. Направена е трансбронхиални биопсия, която показва множество малки интерстициални грануломи, без казеозна некроза. Най-вероятната диагноза е:</p><ul><li><strong>Саркоидоза</strong></li><li>Хистоплазмоза</li><li>Берилиоза</li><li>Интерстициална пневмония</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>50.</strong> 36-годишна жена се оплаква от прогресираща диспнея от няколко години. Няма данни за кашлица или значима експекторация. Рентгенографията показва увеличен белодробен обем, изглаждане на диафрагмалните куполи двустранно и проминираща дясна сърдечна граница. Компютър-томографското изследване установява емфизематозни промени във всички белодробни полета. Коя от изброените лабораторни находки най-добре би могла да обясни тази клинична и образна картина:</p><ul><li><strong>Намален алфа 1 - антитрипсин</strong></li><li>Намален серумен церулоплазмин</li><li>Повишени хлориди при потен тест</li><li>Положителен уринен тест за опиати</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>51.</strong> 50-годишен мъж, дългогодишен пушач, забелязал напоследък кръв в обичайните си иначе храчки. Цитологичното изследване на храчките показва наличие на клетки с атипизъм и хиперхромни ядра. Лабораторно е установено повишаване на серумния калций. Най вероятно рентгенографията ще покаже:</p><ul><li><strong>Туморен процес, разположен централно (прихилусно)</strong></li><li>Пневмония</li><li>Централно разположена ехинококова киста</li><li>Възловидно задебеляване на плеврата</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>52.</strong> Поради асистолия на 58-годишен мъж, непушач, е проведена кардиопулмонална рисусцитация и той е откаран в болница, където е интубиран. По време на интубацията той аспирира стомашно съдържимо. Състоянието се овладява, но на 10-я ден пациентът е с температура 37,9 0 С и непродуктивна кашлица. Рентгенографията на белите дробове показва 4 см сянка с хидроаерично ниво в десния бял дроб. Оцветяването на храчката по Грам установява смесена бактериална флора. Кое от изброените състояния е най вероятно:</p><ul><li><strong>Белодробен абсцес</strong></li><li>Плоскоклетъчен карцином</li><li>Хроничен бронхит</li><li>Бронхиектазии</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>53.</strong> 66-годишна жена се оплаква от засилваща се непродуктивна кашлица, субфебрилна температура и неразположение от няколко седмици. Рентгенографията на белите дробове установява двустранни дифузни интерстициални засенчвания във всички белодробни полета. Цитологичното изследване на храчка установява нормална бактериална флора, епителни клетки и единични левкоцити. Пациентката се възстановява след две седмици като последвалата рентгенография не установява остатъчни промени. Коя от долуизброените инфекции най-вероятно е имала жената:</p><ul><li><strong>Influenza, type A</strong></li><li>Mycobacterium tuberculosis</li><li>Streptococcus pneumoniae</li><li>Cryptococcus neoformans</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>54.</strong> 58-годишен мъж се оплаква от непродуктивна кашлица, засилила се през последните два месеца. Напоследък забелязал кървави жилки в храчките. Рентгенографското изследване установява 5 см сянка близо до левия хилус. В цитологичния препарат от храчка се виждат хиперхромни, полиморфни клетки с оскъдна цитоплазма. Кой от изброените етиологични фактори най-вероятно е довел до заболяването на болния:</p><ul><li><strong>Тютюнопушене</strong></li><li>Силикоза</li><li>Азбестоза</li><li>Експозиция на газ радон</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>55.</strong> 41-годишен мъж се оплаква от загуба на тегло (10 кг за последните 3 месеца), фебрилна температура и диспнея от няколко дни. На рентгенографията се виждат петнисти засенчвания в двата бели дроба. От лабораторните изследвания - левкоцитоза и CD4 лимфоцитите са 79/microliter (при норма 440 - 1600/microliter ). От изпражненията му е изолиран криптоспоридиум. На цитологичен материал от бронхиолоалвеоларният лаваж(БАЛ) се вижда розов, пенест ексудат с малък брой възпалителни клетки. От изброените находки коя най-вероятно ще бъде установена при допълнителните изследвания?</p><ul><li><strong>Множество цисти, визиулизиращи се добре при оцветяване с GMS (Gomori-methenamine stain)</strong></li><li>Бацили, оцветятащи се в червено с Цил-Нилсен или acid-fast</li><li>Септирани хифи</li><li>Макрофаги, натоварени с хемосидерин</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>56.</strong> Страстен пушач на 60-години през последните 5 години има почти постоянна кашлица с обилна слузна експекторация. През това време прекарал две бронхопневмонии - изолирани са Streptococcus pneumoniae и Escherichia coli. Последната бронхопневмония се усложнява със септикопиемия и мозъчни абсцеси, от които загива. При аутопсията се установява, че бронхите са с фиброзно уплътнена стена, задебелена базална мембрана на епитела, плоскоклетъчна метаплазия, хиперплазия и хипертрофия на слузните жлези. Кое от изброените състояния най-добре обяснява клиничното протичане на заболяването, усложненията и описаните морфологични промени?</p><ul><li><strong>Хроничен бронхит</strong></li><li>Плоскоклетъчен карцином</li><li>Застойна сърдечна недостатъчност</li><li>Бронхиална астма</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>57.</strong> 66-годишен пенсиониран строителен инженер се оплаква от засилваща се диспнея с давност около 1 година . Рентгенографията показва билатерални диафрагмално разположени плеврални плаки, както и данни за лека дифузна интерстициална фиброза. Цитологичното изследване на храчка не установява атипични клетки. Тази находка най-вероятно се дължи на експозиция на:</p><ul><li><strong>Азбест</strong></li><li>Памучни влакна</li><li>Силициев двуокис</li><li>Берилий</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>58.</strong> 58-годишен мъж, пушач от дълги години съобщава за загуба на тегло (10 кг през последните 6 месеца) и хронична кашлица. Не е имал температура, гадене и повръщане. Наскоро е имал епизод на хемоптое. Рентгенографски се вижда сравнително добре отграничена окръглена сянка с диаметър 5 см, разположена медиално в горния дял на левия бял дроб. Бронхоскопски се установява лезия, ангажираща левия горен сегментен бронх. Коя от изброените находки ще покаже цитологичното изследване най-вероятно:</p><ul><li><strong>Малигнени епителни клетки в бронхиалната четка</strong></li><li>Плеврален излив с атипични мезотелни клетки</li><li>Епителоидни клетки и некротичен детрит в БАЛ</li><li>Вътреядрени включвания в големи епителни клетки в храчка</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>59.</strong> 44-годишен мъж с анамнеза за хроничен алкохолизъм. Оплаква се от загуба на тегло (12 кг за 5 месеца), кашлица, хемоптое и плеврална болка. Ретгенографията показва ретикулонодуларен тип промени. Направена е трансбронхиална биопсия и микроскопското изследване установява епителоидни клетки и аморфни некротични материи. Коя от изброените находки е най-вероятна при допълнителното хистологично изследване:</p><ul><li><strong>Червено оцветяващи се с Цил-Нилсен и acid-fast бацили</strong></li><li>Септирани хифи</li><li>Полиморфни клетки с тъмни, ъгловати ядра</li><li>Малки, окръглени хиперхромни клетки с висок ядрено-цитоплазмен индекс</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>60.</strong> 20-годишен младеж пада на тротоара по време на сутрешния си крос и охлузва леко лявата си ръка. След няколко минути обаче се появява остър задух и болка в дясната гръдна половина. Минувачи повикват линейка. При пристигането в болницата младежът е с тахипнея и тахикардия. Рентгенографски се вижда изместен на ляво медиастинум, не се установяват фрактури на ребра. При десностранната торакоцентеза от гръдния кош със свистене излиза въздух. Кое от долуизброените състояния е най-вероятната причина за описаната картина:</p><ul><li><strong>Парасептален емфизем</strong></li><li>Бронхоплеврална фистула</li><li>Аспирация на чуждо тяло</li><li>Неалергична (ендогенна) астма</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>61.</strong> 30-годишен мъж претърпява пътно-транспортно произшествие с обилна кръвозагуба, довела до продължителна и изразена хипотенсия. Поставен е на изкуствена белодробна вентилация, но не може да бъде адекватно оксигениран, въпреки покачващите се РЕЕР(positive end-expiratoty pressure) и 100% концентрация на кислород. Остава афебрилен. Загива няколко дни по-късно. При аутопсията в белите дробове се установяват дифузни хиалинни мембрани, задебелени алвеоларни стени, множество алвеоларни макрофаги и оскъдни левкоцити. Тази находка е най-характерна за:</p><ul><li><strong>Дифузна алвеоларна увреда</strong></li><li>Бронхопневмония</li><li>Вирусна пневмония</li><li>Бронхиектазии</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>62.</strong> 51-годишен мъж се оплаква от лека кашлица с давност 1 седмица. Не е пушач, не си спомня да е имал температура или неразположение. Аускултацията установява двустранно чисто везикуларно дишане. На рентгенографията се вижда малка, кръгла сянка (\"coin lesion\"), разположена субплеврално в горния лоб на десния бял дроб. Най-вероятната диагноза е:</p><ul><li><strong>Гранулом</strong></li><li>Дребноклетъчен карцином</li><li>Бронхиектазии</li><li>Силикоза</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>63.</strong> 60-годишен мъж се оплаква от слабо продуктивна кашлица. Рентгенографията показва подобно на пневмония уплътнения в горен десен лоб. Назначена е антибиотична терапия, но след месец рентгенографската картина е непроменена и кашлицата персистира. Направен е бронхиолоалвеоларния лаваж и цитологичното изследване открива атипични клетки и необилни макрофаги. Най-вероятната диагноза е:</p><ul><li><strong>Бронхиолоалвеоларен карцином</strong></li><li>Микоплазмена пневмония</li><li>Саркоидоза</li><li>Белодробен инфаркт</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>64.</strong> 55-годишна жена се оплаква от температура, загуба на тегло и диспнея от няколко месеца. Рентгенографското изследване показва ретикуронодуларен тип на увреждане и хилусна лимфаденомегалия. Направена е трансбронхиална биопсия и хистологичното изследване не установява гъбичкови микроорганизми, вирусни включвания и атипични клетки. Кое от изброените заболявания е най-вероятно:</p><ul><li><strong>Саркоидоза</strong></li><li>Азбестоза</li><li>Силикоза</li><li>Туберкулоза</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>65.</strong> 12-годишно момиче с пристъп на диспнея, бронхоспазъм, тахипнея и тахикардия. Съобщава за подобни епизоди в миналото с продължителност от 1 до няколко часа. Изхрачва голяма, отливъчна храчка от сгъстена слуз. Рентгенографията показва хипервентилация и липса на инфилтрати. От лабораторните изследвания на кръвта - еозинофилия. Кое от долуизброените заболявания би дало подобна картина:</p><ul><li><strong>Бронхиална астма</strong></li><li>Микоплазмена пневмония</li><li>Муковисцидоза</li><li>Хиперсенситивен пневмонит</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>66.</strong> 40-годишна жена, непушачка, здрава до заболяването се оплаква от температура, непродуктивна кашлица и диспнея от няколко месеца. Рентгенографията показва дифузни и нодуларни инфилтрати. Симптомите изчезнали след едномесечна ваканция и се появили отново, когато се прибрала в къщи, за да се погрижи за канарчетата си. Тя най-вероятно страда от заболяване свързано с:</p><ul><li><strong>Антиген-антитяло комплекси</strong></li><li>Дегранулация на мастоцити</li><li>Прогресираща интерстициална фиброза</li><li>Пролиферация на Лангерхансови клетки</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>67.</strong> 54-годишен мъж се оплаква от засилващ се задух през последните няколко години. Афебрилен. Рентгенографията показва: повишена прозрачност в горните отдели на белите дробове, увеличен белодробен обем и изглаждане на диафрагмалните куполи, липсват инфилтрати, уголемени и двустранно проминиращи белодробни съдове, увеличени десни кухини на сърцето. В големите клонове на белодробната артерия най-вероятно ще се открият:</p><ul><li><strong>Атеросклероза</strong></li><li>Организирани тромбоемболи</li><li>Дисекация (разслояване) на медията</li><li>Аневризма</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>68.</strong> 44-годишна жена, непушачка, се оплаква от температура и кашлица през последните няколко дни. Рентгенографията показва инфилтративен (пневмоничен) участък с приблизителни размери 6 см в горния десен лоб. Назначена е антибиотична терапия, но кашлицата персистира. Няма хемоптое. След месец на нова рентгенография отново се очертава периферна лезия в горния десен лоб. Не съобщава за загуба на тегло, гадене или повръщане. Коя от изброените неоплазми най-вероятно е налице:</p><ul><li><strong>Аденокарцином</strong></li><li>Плоскоклетъчен карцином</li><li>Дребноклетъчен карцином</li><li>Мезотелиом</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>69.</strong> 70-годишна жена е на легло от няколко седмици след мозъчно-съдов инцидент. Оплаква се от остър пристъп на задух. След два дни се оплаква от болка в лявата гръдна половина. Загива ден по-късно след нов мозъчно-съдов инцидент. На аутопсията в долния ляв лоб на белия дроб се намира участък с вид на кръвоизлив, с приблизително триъгълна форма, обхващащ и плеврата. Кой от изброените механизми обяснява белодробната находка:</p><ul><li><strong>Оклузия на средно-калибрен клон на белодробната артерия</strong></li><li>Яздещ тромб на белодробната артерия</li><li>Белодробно сърце</li><li>Васкулит, ангажиращ малки разклонения на белодробната артерия</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>70.</strong> 38-годишна жена, без значими заболявания в миналото, се оплаква от засилваща се непродуктивна кашлица през последните 4 дни. На рентгенографията се виждат петнисти засечвания от ацинарен тип и фини ретикуларни засенчвания (усилен белодробен рисунък). Микробиологичното изследване на храчка установява смесена бактериална флора. Липсва периферна левкоцитоза. Увеличен е титърът на студови аглутинини. След курс лечение с еритромицин тя се възстановява без усложнения. Кой от изброените инфекциозни агенти най-вероятно е причинил заболяването:</p><ul><li><strong>Mycoplasma pneumoniae</strong></li><li>Nocardia asteroides</li><li>Respiratory syncytial virus</li><li>Chlamydia psittici</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>71.</strong> 44-годишен мъж, здрав до заболяването, получил остро настъпил, тежък задух. На рентгенографията се вижда колапс на десния бял дроб. Най-вероятно това е резултат от:</p><ul><li><strong>Пенетрираща гръдна травма</strong></li><li>Аспирация на чуждо тяло</li><li>Белодробен тромбоемболизъм</li><li>Плоскоклетъчен карцином</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>72.</strong> 65-годишен мъж не е имал сериозни здравословни проблеми до преди 1 година, когато забелязал засилващо се неразположение, отпадналост и загуба на тегло - 10 кг. Не е пушач. Не съобщава за температура, кашлица или задух. При физикалното изследване се открива плътен, увеличен супраклавикуларен лимфен възел. Чисто везикуларно дишане. На ретгенографията се вижда множество солидни възли с размери от 1 до 3 см във всички белодробни полета. От лабораторните изследвания - лека нормоцитна анемия. Кой от изброените патологични процеси е най-вероятен:</p><ul><li><strong>Метастатичен карцином</strong></li><li>Белодробни инфаркти</li><li>Аспирация на чужди тела</li><li>Силикоза</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>73.</strong> 43-годишна жена, непушачка, се оплаква от засилваща се диспнея през последните няколко години. Тя е афебрилна, няма кашлица и експекторация. Рентгенографията показва повишена прозрачност във всички белодробни полета. Серумният алфа-1 антитрипсин е 18 mg/dl (при норма 100-200 mg/dl). Коя част от белите дробове ще бъде засегната:</p><ul><li><strong>Алвеоларни ходове</strong></li><li>Лимфните пътища</li><li>Бронхиални артерии</li><li>Терминални бронхиоли</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>74.</strong> 6-годишно дете е аспирирало фъстъчена ядка. Детето може да развие всички от изброените състояния с изключение на:</p><ul><li><strong>Криптококова пневмония</strong></li><li>Ателектази</li><li>Ендогенна липидна пневмония</li><li>Бронхиектазия</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>75.</strong> 47-годишна жена развива остра бъбречна недостатъчност. Направена е бъбречна биопсия и се установява полулунен гломерулонефрит. Лабораторно се доказва положителен тест за антибазалномембранни антитела. Рентгенографията показва двустранни пръснати пенести сенки. Цитологичното изследване на храчка установява наличие на натоварени с пигмент макрофаги на фона на множество еритроцити, без атипични клетки. Коя от изброените патологични находки в белите дробове е най-вероятна:</p><ul><li><strong>Синдром на Goodpasture</strong></li><li>Рецидивираща белодробна тромбоемболия</li><li>Плеврален излив</li><li>Неказеифициращи грануломи</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>76.</strong> 29-годишен мъж е HIV позитивен през последните 8 години. Оплаква се от температура, непродуктивна кашлица и задух от няколко дни. Рентгенографията показва двустранни обширни инфилтративни засенчвания. Направен е бронхиоло-алвеоларен лаваж. Кой от изброените микроорганизми най-вероятно ще се установи:</p><ul><li><strong>Pneumocystis carinii (P. jirovecii)</strong></li><li>Cryptococcus neoformans</li><li>Aspergillus fumigatus</li><li>Hemophilus influenzae</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>77.</strong> 47-годишна жена има плътна, недобре отграничена 1 см лезия с микрокалцификати в дясната гърда, установена мамографски. Палпират се увеличени аксиларни лимфни възли. Оплаква се от затруднено дишане. Рентгенографията показва голям двустранен плеврален излив. Направена е торакоцентеза и е изпратена кървениста течност за цитологично изследване. Какво най-вероятно ще се установи в тази течност:</p><ul><li><strong>Групи от карциномни клетки</strong></li><li>Грам-негативни бацили</li><li>Атипични мезотелни клетки</li><li>Голям брой малки лимфоцити</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>78.</strong> 45-годишен мъж се оплаква от засилваща се диспнея. Рентгенографията показва голям двустранен плеврални излив. При торакоцентезата се отделя 500 мл серозно-хеморагичен ексудат. Кое от изброените заболявания е най-малко вероятната причина за излива:</p><ul><li><strong>Сърдечна недостатъчност</strong> (Тя обикновено причинява трансудат, а не хеморагичен ексудат)</li><li>Карциномни метастази</li><li>Бронхогенен карцином</li><li>Белодробен инфаркт</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>79.</strong> 60-годишна жена, пушачка от 18 г. възраст, има хронична кашлица от много години. През последните две седмици е имала няколкократни епизоди на хемоптое. Рентгенографията показва недобре очертана лезия в десния хилус. Трансбронхиалната тънкоиглена биопсия установява групи от малки, хиперхромни клетки с оскъдна цитоплазма. Коя от изброените лабораторни находки е най-вероятна:</p><ul><li><strong>Хипонатриемия</strong> (Поради SIADH, често свързан с дребноклетъчен карцином)</li><li>Антинуклеарни антитела</li><li>Хипербилирубинемия</li><li>Хиперкалциемия</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>80.</strong> 10-годишно дете е прекарало няколко пневмонии с изолирани Hemophilus influenzae и Enterococcus. Рентгенографията показва ограничен уплътнен участък близо до основата на десния бял дроб. Ангиографията установява, че този сегмент на белия дроб се снабдява с артериална кръв от системното, а не белодробното кръвообръщение. Най-вероятното обяснение за това е:</p><ul><li><strong>Белодробна секвестрация</strong></li><li>Кистична фиброза</li><li>Бронхогенна киста</li><li>Хронична абсцедираща пневмония</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>81.</strong> 27-годишна жена се оплаква от прогресираща диспнея и синкопи при физически усилия през последните две години. Не се установяват промени при аускултация на белите дробове и сърцето. Загива внезапно. На аутопсията се установява хипертрофия на дясната камера, изразена атеросклероза на белодробната артерия и плексиформена белодробна артериопатия. Най-вероятното обяснение на тези находки е:</p><ul><li><strong>Първична белодробна хипертония</strong></li><li>Първична атипична пневмония</li><li>Синдром на Гудпасчър</li><li>Захарен диабет</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>82.</strong> 45-годишна жена се оплаква от засилваща се диспнея и отпадналост през последните няколко месеца. Отслабнала 5 кг. Рентгенографията показва голям десностранен плеврален излив. При торакосинтезата изтича 650 мл подобен на прясно мляко ексудат. Най-вероятната причина за това е:</p><ul><li><strong>Медиастинален малигнен лимфом</strong> (Причинява хилоторакс чрез оклузия на дуктус торацикус)</li><li>Туберкулоза</li><li>Системен лупус еритематодес</li><li>Пенетрираща травма на гръдния кош</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>83.</strong> 36-годишна жена се оплаква от остро настъпили температура, кашлица и задух, след един ден работа в стара бизнес сграда. Работи като стенограф на повикване. Имала е подобни оплаквания всеки път, когато е работила в тази сграда през последните 6 месеца. Приета е в болница поради белодробното заболяване и е направена трансбронхиална биопсия. Хистологичното изследване установява огнищен (перибронхиален) интерстициален пневмонит (лимфоцити, плазматични клетки, макрофаги). Кое от изброените заболявания е най-вероятно:</p><ul><li><strong>Хиперсензитивен пневмонит</strong></li><li>Грипна пневмония</li><li>Бронхиална астма</li><li>Пневмоцистна пневмония</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>84.</strong> 53-годишен мъж, хроничен алкохолик, отслабнал с 10 кг през последните 3 месеца. Имал е хронична кашлица с оскъдно хемоптое, субфебрилна температура и нощни изпотявания. Намерен е от съседи починал в апартамента си. По време на аутопсията се установяват стотици малки (от 1 до 3 мм) окръглени възелчета в белите дробове. Кой от изброените инфекциозни причинители най-вероятно е довел до тази макроскопска находка:</p><ul><li><strong>Mycobacterium tuberculosis</strong> (Милиарна туберкулоза)</li><li>Pneumocystis carinii</li><li>Respiratory syncytial virus</li><li>Aspergillus fumigatus</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>85.</strong> 56-годишен мъж не е търсил медицинска помощ и не е ходил при личния си лекар от години. Съобщава за умора при по-сериозни физически усилия от 5 г. От време на време е имал болка в гърдите при изкачване на стълби. Пуши 2 кутии цигари дневно. Установява се RR 155/95 mm Hg. Body mass index 30. Лабораторните изследвания показват повишен общо холестерол и намалени HDL. Коя от изброените съдови промени представлява най-сериозен риск за пациента.</p><ul><li><strong>Атеросклероза</strong></li><li>Хиперпластна артериолосклероза</li><li>Дълбока венозна тромбоза</li><li>Медиокалциноза на артериални съдове</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>86.</strong> От 14 дни лекувате в болница 55-годишна жена за пневмония. Пациентката не е имала значими заболявания до хоспитализацията. Откривате оток и болезненост на десния крак, развили се в последните 48 часа. Повдигането на крака засилва болката. Ехографското изследване дава данни за феморална тромбоза. Кое от изброените състояние е допринесло най-много за нейното развитие.</p><ul><li><strong>Продължителна имобилизация</strong></li><li>Аденокарцином на панкреаса със синдром на Трусо</li><li>Протеин С недостатъчност</li><li>Хроничен алкохолизъм</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>87.</strong> 63-годишен мъж с инсулинозависим захарен диабет от 20 години с лош контрол (Hb A1С 10,1%). Оплаква се от коремни болки след нахранване. Оплакванията зачестили през последните няколко години. Физикалното изследване не установява туморна формация, органомегалия или болка при палпация. Кое от изброените заболявания най-вероятно е причина за оплакванията му.</p><ul><li><strong>Стеноза на мезентериални съдове</strong> (т.нар. \"коремна ангина\" вследствие на атеросклероза)</li><li>Руптура на аортна аневризма</li><li>Хронична бъбречна недостатъчност</li><li>Остър панкреатит</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>88.</strong> 29-годишна жена претърпява пътно-транспортно произшествие с тъпа коремна травма и значителна загуба на кръв. Кое от изброените е най-малко вероятно да се установи в последващите 72 часа.</p><ul><li><strong>Диспнея с рентгенови данни за белодробен инфаркт</strong> (инфарктът е рядък поради дуалното кръвоснабдяване, освен ако няма масивна емболия по-късно)</li><li>Студена, бледа кожа.</li><li>Изпражнения, положителни при тест за окултни кръвоизливи</li><li>Олигурия</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>89.</strong> В интензивно кардиологично отделение е приет 54-годишен мъж с остро настъпила болка в гърдите и ЕКГ данни за остър миокарден инфаркт. Приложена е тромболитична терапия с tPA - тъканен плазминогенен активатор. Няколко часа след лечението се установява серумна креатин киназа 450 U/L. Кое от изброените е най-вероятната причина за това:</p><ul><li><strong>Реперфузионна увреда</strong> (tPA отваря съда, което води до \"измиване\" на ензимите от некротичните клетки в циркулацията)</li><li>Клетъчна регенерация</li><li>Химична увреда</li><li>Повишена секреция на креатин-киназа</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>90.</strong> Кое от изброените усложнения е НАЙ-МАЛКО ВЕРОЯТНО да се случи на 49-годишна жена, която е развила генерализирана атеросклероза през последните 20 г.</p><ul><li><strong>Атеросклероза на артерия пулмоналис</strong> <span style=\"color: rgb(0, 176, 80)\">(белодробната артерия се засяга само при тежка белодробна хипертония, не при системна атеросклероза</span>)</li><li>Внезапна смърт</li><li>Гангрена на големия пръст на десния крак</li><li>Цикатрикс след миокарден инфаркт</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>91.</strong> При аутопсия бъбреците са с обичайна големина, фина дребна зърнистост на повърхността и малки огнищни хеморагии. Кората е бледа. Микроскопски се установява концентрично интимално задебеляване и изразена стеноза на лумена на малки артерии и артериоли. Бъбреците най-вероятно принадлежат на:</p><ul><li><strong>44 г. жена със склеродермия и високостепенна хипертония</strong> (<span style=\"color: rgb(0, 176, 80)\">картина на малигнена нефросклероза</span>)</li><li>54 г. мъж с ХБН и амилоидоза</li><li>29 г. жена с протеинурия и лупусен нефрит</li><li>5 г. дете с липоидна нефроза</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>92.</strong> Тежка коронарна атеросклероза е довела до остър миокарден инфаркт при 55-годишен мъж. Кой от изброените факти е НАЙ-МАЛКО ВЕРОЯТНО да е свързан с развитието на инфаркта.</p><ul><li><strong>Намалено количество на липопротеин и с ниска плътност (LDL) в кръвта</strong> (<span style=\"color: rgb(0, 176, 80)\">напротив, високият LDL е рисков фактор</span>)</li><li>Адхезия на тромбоцити върху увредената интима в област с липидни петна</li><li>Руптура на интималната плака и образуване на тромб</li><li>Миграция и пролиферация на гладкомускулни клетки</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>93.</strong> 45-годишен мъж почувствал силна болка в гърдите и скованост на лявата ръка по време на почистване на дълбок сняг пред къщата си. По-късно същия ден колабирал. Доведен е в спешния център 12 часа след инцидента. Кой от изброените лабораторни кръвни тестове би бил най-информативен в подобна ситуация:</p><ul><li><strong>Креатин киназа (CK-MB)</strong> (<span style=\"color: rgb(0, 176, 80)\">или Тропонин, ако беше наличен в списъка</span>)</li><li>Глюкоза</li><li>Броя на тромбоцити</li><li>Амилаза</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>94.</strong> 68-годишна жена преживяла многократни епизоди на белодробен тромбоемболизъм през последните три месеца. Кое от изброените състояния е най-вероятно да е допринесло за това:</p><ul><li><strong>Дълбока венозна тромбоза на долните крайници</strong> (основен източник на белодробни емболи)</li><li>Микронодуларна цироза</li><li>Митрален ендокардит</li><li>Намален брой тромбоцити</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>95.</strong> 64-годишен мъж има оклузивна коронарна атеросклероза с тромбоза. Кое от изброените твърдения е най-малко вероятно:</p><ul><li><strong>Анамнеза за хроничен алкохолизъм</strong> (алкохолизмът не е директен патогенетичен фактор за атеросклерозата така, както са диабетът или хиперлипидемията)</li><li>Общият серумен холестерол е повишен</li><li>Има захарен диабет тип I</li><li>Починал е внезапно</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>96.</strong> 70-годишен мъж забелязал, че през последните няколко месеца левият му крак изстива и се схваща. Съобщава за необходимост от чести почивки поради болка при изминаване на по-големи разстояние. При физикалното изследване не установявате пулс на артерии дорзалис педис, тибиалис постериор и поплитеа. Коя от изброените лабораторни находки има връзка с предполагаемата диагноза:</p><ul><li><strong>Хипергликемия</strong></li><li>Дефицит на протеин С</li><li>Изолиран от кръвта Стафилококус ауреус</li><li>Намалена кислородна сатурация на кръвта</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>97.</strong> 45-годишен мъж е приет по спешност в интензивно отделение по повод на разкъсваща ретростернална болка. По време на пролежаването е в кардиогенен шок, който не може да бъде овладян. Загива на 4-я ден от инцидента. На аутопсията се установява голям участък с коагулационна некроза, разположен предно-латерално. Хистологичната находка ще установи:</p><ul><li><strong>Некротични миофибри и неутрофилни левкоцити</strong></li><li>Фибробласти и колаген</li><li>Гранулационна тъкан</li><li>Грануломатозно възпаление</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>98.</strong> 45-годишна жена е с ортопнея от няколко години. Съобщава за затруднения в гълтането. Не е имала болки в гърдите. Афебрилна. Преди няколко месеца е прекарала \"удар\" с остатъчна левостранна хемиплегия. Рентгенографията на белия дроб установява нормални размери на лявата сърдечна камера и силно дилатирано ляво предсърдие. Кое от изброените заболявания е най-вероятно:</p><ul><li><strong>Стеноза на митралната клапа</strong></li><li>Есенциална хипертония</li><li>Кардиомиопатия</li><li>Коарктация на аортата</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>99.</strong> 72-година жена, без сериозни заболявания до момента, от две седмици се оплаква от задух и кашлица с пенеста бяла експекторация. Имала е и няколко синкопални пристъпа. Афебрилна. Без периферни отоци. Серумен холестерол в норма. RR 135/90 mm Hg. Рентгенографията на белия дроб открива белодробен оток, леко изместена наляво сърдечна граница. Кое заболяване бихте подозирали на първо място:</p><ul><li><strong>Калцифицираща аортна стеноза</strong></li><li>Остър ревматизъм</li><li>Митрална стеноза</li><li>Атеросклеротична аортна аневризма</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>100.</strong> 65-годишен мъж с 20 годишна анамнеза за диабет е приет в болница по повод на остра настъпила коремна болка. Физикалното изследване установява отслабен пулс на долните крайници и пулсираща коремна маса. Серумната му креатин киназа не е увеличена. Кое от изброените заболявания е най-вероятно:</p><ul><li><strong>Атеросклеротична коремна аневризма</strong></li><li>Тромбоза на арт. мезентерика супериор</li><li>Панартериитис нодоза</li><li>Медиокалциноза на Мьонкеберг</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>101.</strong> 23-годишна жена се оплаква от неразположение и пеперудообразен обрив по лицето от няколко месеца. Установява се повишен титър на антинуклеарни антитела. Аускултира се перикардно триене и слаб систоличен шум. Ехокардиографското изследване установява малки вегетации по двете страни на митралната клапа и прилежащия вентрикуларен ендокард. Тя най-вероятно има:</p><ul><li><strong>Дисеминиран лупус еритематодес</strong></li><li>Панартериитис нодоза</li><li>Системна склеродермия</li><li>Грануломатоза на Вегенер</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>102.</strong> При ехографското изследване на плод в 18-та гестационна седмица се установява,че фетусът е с нормални за гестационната възраст размери. Черепът, бъбреците, черният дроб и крайниците изглеждат нормални. Сърцето на плода, обаче, е с мембранозен вентрикуларен септален дефект, яздеща аорта и изразена пулмонална стеноза. Ако бебето се роди живо, коя от описаните физиологични промени ще бъде налице:</p><ul><li><strong>Цианоза</strong></li><li>Системна хипертония</li><li>Слаб пулс на долните крайници</li><li>Телеангиектазии</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>103.</strong> 25-годишна физически здрава жена почива скоропостижно. Оплаквала се е само от леко главоболие през последните няколко дни. По време на аутопсията, съдебният лекар открива уголемено и дилатирано сърце с минимална коронарна атеросклероза и нормални сърдечни клапи. Микроскопски миокардът на лявата и дясна камера показва лимфоцитна инфилтрация и огнищни некрози на отделни кардиомиоцити. Кой от изброените инфекциозни агенти най-вероятно е причинил тези промени:</p><ul><li><strong>Coxsackie B virus</strong></li><li>Candida albicans</li><li>Aspergillus fumigatus</li><li>Streptococcus viridans</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>104.</strong> 42-годишна жена с прогресираща сърдечна недостатъчност като дете е боледувала често от фарингити с бета хемолитичен стрептокок от група А. Кои сърдечни клапи най-вероятно са засегнати при пациентката:</p><ul><li><strong>Митрална и аортна</strong></li><li>Аортна и трикуспидална</li><li>Митрална и пулмонална</li><li>Трикуспидална и пулмонална</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>105.</strong> 65-годишна жена, заклет пушач, има прогресираща диспнея от няколко години без значима кашлица. Рентгенографията на белите дробове показва увеличена прозрачност и размери на белите дробове и изглаждане на диафрагмалните куполи, картина съответстваща на белодробен емфизем. През следващите няколко години се появяват засилващи отоци по долните крайници. Физикалното изследване установява RR 115/70, пулс 77/мин. Кое от изброените състояния най-вероятно е налице:</p><ul><li><strong>Хипертрофия на дясната камера</strong></li><li>Стеноза на митралната клапа</li><li>Констриктивен перикардит</li><li>Аневризма на лявата сърдечна камера</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>106.</strong> В клиниката установявате кръвно налягане при 61-годишен мъж 183/100 mm/Hg в седнало положение и 190/100 mm/Hg изправен, сърдечна честота 81/мин, абсолютна аритмия, влажни хрипове в двете белодробни основи, без сърдечни шумове. Кое от изброените патологични състояния най-вероятно е налице:</p><ul><li><strong>Хипертрофия на лявата сърдечна камера</strong></li><li>Белодоробно сърце</li><li>Митрална регургитация</li><li>Миксом на лявото предсърдие</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>107.</strong> 59-годишен мъж, много активен през целия си живот, получава внезапна остра болк в гръдния кош с ирадиация към гърба. След минути изпада в безсъзнание. Пациентът има анамнеза за артериална хипертония. Направеният наскоро преди инцидента тест с натоварване не показва данни за сърдечно заболяване. Кое от изброените ще подозирате:</p><ul><li><strong>Разкъсване на аортната интима</strong></li><li>Белодробна тромбоемболия</li><li>Остър вирусен миокардит</li><li>Ембол в артерия церебри медия</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>108.</strong> 27-годишен мъж наркоман, пристрастен към хероин, се оплаква от треска от няколко дни. При аускултацията установявате аортен холосистоличен шум. Под ноктите на ръцете му има малки, продълговати кръвоизливи. Ехокардиографски установявате вегетации по аортната клапа. Кое от изброените усложнения е най-малко вероятно при тази клинична картина:</p><ul><li><strong>Хемоперикард</strong></li><li>Застойна сърдечна недостатъчност</li><li>Инфаркт на слезката</li><li>Клапна недостатъчност</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>109.</strong> 7-месечно дете развива прогресираща застойна сърдечна недостатъчност. Детето е родено доносено и до 5-я месец се е развивало добре. Няма фамилна анамнеза за вродени или сърдечни заболявания на родителите. Състоянието се влошава и детето загива. На аутопсията се установява уголемено сърце с изразено задебеляване на ендокарда на лявата камера с облитерация на хорде тендинее. Сърдечните клапи са без промени. Кое от долните твърдения е най-вероятно:</p><ul><li><strong>Състоянието е идиопатично</strong></li><li>Инфекция със стрептококи от група А</li><li>Вродено метаболитно заболяване (тезауризмоза)</li><li>Диабет на майката</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>110.</strong> 46-годишна жена се оплаква от грозно изглеждащи, разширени вени на долните крайници, които нараснали през последните 5 години. Кожата на подбедриците е огрубена и бледокафеникава, но не е улцерирана. Не установявате оток на долните крайници. От изброените твърдения са верни всички, с ИЗКЛЮЧЕНИЕ на:</p><ul><li><strong>Те са значим източник на тромбоемболи</strong></li><li>Най-често фамилни, когато се открият в по-млади пациенти</li><li>Не могат да бъдат премахнати по хирургичен път</li><li>По-чести са при жени</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>111.</strong> Близките на 51-годишен мъж забелязват внезапна промяна в психичното състояние. Компютър-томографски се установява десностранен субарахноидален кръвоизлив. Състоянието му прогресивно се влошава и той загива с картината на мозъчен оток с вклиняване. По време на аутопсията се установява остро възпаление с огнищна аневризмална дилатация и руптура на дясната париетална церебрална артерия. Най-вероятно това е усложнение на:</p><ul><li><strong>Ендокардит на аортната клапа, причинен от Staphylococcus aureus</strong></li><li>Синдром на Марфан</li><li>Метастатичен аденокарцином</li><li>Панартериитис нодоза</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>112.</strong> Преглеждате 49-годишна жена с изразени отоци по подбедриците и шиен венозен застой до ъгъла на долната челюст. Назначавате рентгенография, която установява двустранни плеврални изливи и проминираща дясна сърдечна граница. Най-малко вероятната етиология за тази находка е:</p><ul><li><strong>Коронарна атеросклероза</strong></li><li>Силикоза</li><li>Недостатъчност на трикуспидалната клапа</li><li>Първична белодробна хипертония</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>113.</strong> 52-годишен мъж се оплаква от стомашен дискомфорт (гадене, повръщания) от много години. Преди 4 години ендоскопското изследване на стомаха е установило хроничен гастрит и наличие на Helicobacter pylori. При настоящото ендоскопско изследване във фундуса на стомаха се вижда малък участък с изглаждане на лигавични гънки. Направената биопсия установява добре диференциран аденокарцином, ограничен само в лигавицата на стомаха. Кое от долните твърдения за тази лезия е вярно:</p><ul><li><strong>5 годишна преживяемост след резекция при повече от 90% от пациентите.</strong></li><li>Наличие на метастази само в регионалните лимфни възли.</li><li>Хистологична картина на клетки тип \"пръстен с камък\".</li><li>Макроскопска картина на линитис пластика.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>114.</strong> По време на операция на 29-годишен мъж с прободно нараняване на корема се установява възел с диаметър 1 см, разположен в субмукозата на илеума. Лезията е отстранена. Макроскопски тя е плътна, добре отграничена, с жълтокафеникав цвят на срезната повърхност. Микроскопски е съставена от гнезда от клетки, с еднакви, малки, кръгли ядра, с неравномерно разпределен хроматин (\"сол и пипер\") и цитоплазма с малки еозинофилни гранули, които са позитивни при имунохистохимично изследване с хромогранин. Коя от изброените допълнителни находки е НАЙ-ВЕРОЯТНА:</p><ul><li><strong>Други подобни лезии</strong></li><li>Наличие на чернодробни метастази</li><li>Болест на Крон</li><li>Аденокарцином на панкреаса</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>115.</strong> 36-годишен мъж се оплаква от болки в епигастриума от няколко месеца. От 2-3 седмици има и гадене. Тестът за окултни кръвоизливи в изпражненията е положителен. Ендоскопското изследване не установява промени в езофага и 2 см, добре отграничена, с гладки надигнати ръбове стомашна язва. Кое от изброените твърдения относно лезията е най-вероятно:</p><ul><li><strong>Най-вероятно е локализирана в антрума на стомаха</strong></li><li>Най-вероятно е малигнена</li><li>Поради малките си размери не е необходимо биопсично изследване</li><li>Най-вероятно пациентът има гастрином на панкреаса</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>116.</strong> 16-годишно момиче се оплаква от остро настъпили болки в горния десен абдоминален квадрант. Ехографското изследване установява дилатиран и изпълнен с конкременти жлъчен мехур. Направена е лапароскопска холецистектомия. В жлъчния мехур се намират множество тъмнозелени до черни конкременти, с диаметър 0,5-1 см. Кои от изброените състояния могат да обяснят тази находка:</p><ul><li><strong>Сърповидноклетъчна анемия</strong></li><li>Хиперпаратироидизъм</li><li>Хиперхолестеролемия</li><li>Първична билиарна цироза</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>117.</strong> 28-годишна, здрава до заболяването жена, се оплаква от остро настъпила епигастрална болка. Физикалното изследване установява болезненост във всички абдоминални квадранти и липса на перисталтика. Серумната амилаза и серумната липаза са завишени. Кое от изброените състояния е НАЙ-МАЛКО ВЕРОЯТНО като етиологичен фактор:</p><ul><li><strong>Муковисцидоза (кистична фиброза)</strong></li><li>Травма</li><li>Вирусна инфекция</li><li>Калкулоза на жлъчния мехур</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>118.</strong> 43-годишен мъж се оплаква от стомашен дискомфорт и гадене от няколко години, които не се повлияват от антиацидни средства. Не съобщава за трудности при преглъщане и киселини след нахранване. Ендоскопското изследване установява хиперемирана антрална лигавица, без улцерации и туморни маси. Взети са няколко късчета от антрума и микроскопското изследване показва наличие на хроничен неспецифичен гастрит. Кое от долу изброените състояния най-вероятно е налице:</p><ul><li><strong>Helicobacter pylori инфекция</strong></li><li>Гастринома (с-м на Цьолингер-Елисън)</li><li>Пернициозна анемия</li><li>Аденокарцинома</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>119.</strong> 32-годишен мъж съобщава за коликообразни коремни болки предимно в долния десен абдоминален квадрант, оскъдна диария и температура през последните няколко седмици. При физикалното изследване се установява болезненост в долен десен абдоминален квадрант и наличие на перисталтика. Тестът за окултни кръвоизливи е положителен. Ендоскопското изследване установява оток и улцерации в лигавицата на колон асценденс, като колон транзверзум и колон десценденс не са засегнати. Коя ще бъде най-характерната микроскопска находка:</p><ul><li><strong>Грануломи</strong></li><li>Крипт абсцеси</li><li>Entameba histolytica микроорганизми</li><li>Аденокарцином</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>120.</strong> 43-годишна жена е с 10 годишна анамнеза за интермитираща, примесена с кръв диария. Не съобщава за други оплаквания и здравни проблеми. Колоноскопията установява ранима, хиперемирана лигавица с огнищни улцерации в ректума, десцендентния колон и части от трансверзалния колон. Промените не са сегментни. При тази пациентка има риск от развитие на:</p><ul><li><strong>Склерозиращ холангит</strong></li><li>Остър панкреатит</li><li>Дивертикулит</li><li>Периректална фистула</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>121.</strong> 36-годишен мъж провежда рутинен медицински преглед поради фамилна анамнеза за карцином на дебелото черво. Не се откриват болезненост или абдоминални туморни маси. Тестът за окултни кръвоизливи е положителен. Направена е колоноскопия, ендоскопска полипектомия и последващо биопсично изследване. В асцендентния колон се установяват 6 полипа - два тубуларни аденома на краче с големина 0,5 см, три тубуловилозни аденоми с големина 1 см и един вилозен аденом в цекума на широка основа с размери 2 см, в който се открива огнище на добре диференциран аденокарцином. Кое от изброените състояния най-добре обяснява тези находки:</p><ul><li><strong>Наследствен неполипозен дебелочревен карциномен синдром</strong></li><li>Синдром на Peutz-Jehgers</li><li>Множествена фамилна полипоза</li><li>Синдром на Gardner</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>122.</strong> 69-годишна жена съобщава за леко пожълтяване на склерите и леко гадене от няколко месеца. Не е имала повишена температура. Когато иктерът станал интензивен тя отива в болница, където се установяват следните промени повишени стойности на алкална фосфатаза, общ билирубин, директен билирубин, AST, ALT(като последните два показатела, не са значимо повишени). Физикалното изследване не установява палпаторна болезненост, добра перисталтика. Тестът за окултни кръвоизливи е отрицателен. Кои от изброените състояние може да обясни тези находки:</p><ul><li><strong>Аденокарцином на панкреаса</strong></li><li>Хроничен хепатит с активност</li><li>Хроничен хепатит без активност</li><li>Първична билиарна цироза</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>123.</strong> 63-годишен мъж е имал анорексия, повръщане и неясни коремни болки. Отслабнал с 12 кг за 2-3 месеца. Физикалното изследване установява не болезнена супраклавикуларна лимфаденопатия. Пациентът умира в състояние на кахексия. По време на аутопсия се намира стомах с намален лумен и дифузно задебелена до 1 см стена с множествени лигавични ерозии. В черния дроб се откриват няколко туморни възела с централно хлътване (\"пъп\") с размери от 1 до 3 см. Кое от изброените състояния НАЙ-ВЕРОЯТНО е предхождало заболяването на пациента:</p><ul><li><strong>Автоимунен гастрит</strong></li><li>HIV инфекция</li><li>Захарен диабет</li><li>Хроничен алкохолизъм</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>124.</strong> 39-годишен мъж, фелдшер в Бърза помощ, се оплаква от отпадналост от няколко месеца. Той си спомня, че е имал период на краткотрайно пожълтяване на склерите преди 10 години, но това преминало и от тогава не е имал оплаквания. Лабораторните изследвания установяват нормални стойности на хемоглобина и еритроцити, значително повишени стойности на ALT и AST, общ билирубин в норма и завишен директен билирубин 0.8 mg/dL. Направената чернодробна биопсия показва умерена кръглоклетъчна инфилтрация в порталните триади, нарушена гранична ламела с навлизане на кръглоклетъчната инфилтрация в лобулите и балонна дегенерация на хепатоцитите. Коя от изброените лабораторни находки е най-характерна за това заболяване:</p><ul><li><strong>Положителен HbsAg в серума</strong></li><li>Намален серумен алфа-1-антитрипсин</li><li>Намален серумен церулоплазмин</li><li>Повишени АМА (антимитохондриални антитела)</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>125.</strong> При палпация на корема се установява уплътнен, но не увеличен черен дроб на 40-годишен мъж. Анамнестичните данни насочват към хроничен алкохолизъм. Компютърната томография открива промени, съответстващи на чернодробна цироза. Пациентът започва лечение и престава да консумира алкохол. Въпреки продължителната абстиненция при него остава повишен рискът от развитие на:</p><ul><li><strong>Хепатоцелуларен карцином на черния дроб</strong></li><li>Аденом на черния дроб</li><li>Холелитиаза</li><li>Ангиосарком на черния дроб</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>126.</strong> 21-годишна жена с тремор, дизартрия и забавено мислене се оплаква от прогресиращо неразположение през последната година. Лабораторните изследвания установяват повишени нива на общ билирубин, директен билирубин, AST, ALT и ниски стойности на серумен церулоплазмин. АМА (антимитохондриални антитела) са негативни. Може да се очаква тя да има всичко от долу изброените с ИЗКЛЮЧЕНИЕ на: </p><ul><li><strong>Множествени церебрални инфаркти</strong></li><li>Отлагане на мед в хепатоцитите </li><li>Повишена екскреция на мед в урината </li><li>Корнеални пръстени на Кайзер-Флайшер </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>127.</strong> 45-годишна жена се оплаква от затруднено преглъщане през последните 5 месеца. Рентгеновотото изследване с бариева каша установята структура в долната трета на хранопровода, непосредствено над Z линията. Направена е горна ендоскопия и щипкова биопсия от засегнатия участък. Хистологичното изследване не установява възпаление или разязвяване, а само субмукозна атрофия и фиброза на гладката мускулатура. Тези находки предполагат наличието на: </p><ul><li><strong>Склеродермия</strong></li><li>Синдром на Малори-Вайс </li><li>Портална хипертония </li><li>Баретов езофаг </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>128.</strong> 23-годишен мъж се оплаква от необилна, хронична, с лоша миризма диария през последната година. Отрича гадене, повръщане или коремни болки. Не съобщава за пътувания в чужбина. Изследването на фекални маси установява стеаторея. Тестът за окултни кръвоизливи е отрицателен. Ендоскопската биопсия на дуоденума показва почти пълна липса на тънкочревни въси (\"гладка лигавица\"), повишен брой лимфоцити сред епителните клетки, удължени, нагънати и хиперпластни крипти. Коя от изброените терапевтични възможности бихте препоръчали: </p><ul><li><strong>Безглутенова диета</strong></li><li>Антибиотици </li><li>Кортикостероиди </li><li>Ваготомия </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>129.</strong> 46-годишен мъж се оплаква от засилващи се коремни болки през последния месец. Съобщава за пристъпни коремни болки в миналото. Анамнезата насочва към хронична злоупотреба с алкохол. Физикалното изследване установява палпаторна болезненост с лек дефанс в горен десен и ляв абдоминален квадрант. Рентгенологичното изследване показва значително количество течност в перитонеалната кухина и дилатирани тънкочревни бримки. Компютъртомографски се визуализира кистична формация с диаметър 7 см в опашката на панкреаса. Най-вероятната диагноза, която може да обясни тези находки е: </p><ul><li><strong>Псевдокиста на панкреса</strong></li><li>Остър панкреатит </li><li>Инсуларноклетъчен аденом на панкреса </li><li>Аденокарцином на панкреаса </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>130.</strong> 52-годишен мъж се оплаква от болка в епигастриума и гадене от няколко месеца. Не съобщава за хематемеза. Тестът за окултни кръвоизливи е отрицателен. Щипковата стомашна биопсия установява леко изразена атрофия на лигавицата, обилна кръглоклетъчна инфилтрация с примес на левкоцити в ламина проприя и наличие на микроорганизми, морфологично съответстващи на Helicobacter pylori. Кое от изброените твърдения, касаещи микроорганизмите е вярно: </p><ul><li><strong>Много често е налице дуоденална язва при наличие на Helicobacter pylori в антралната мукоза</strong></li><li>Микроорганизмите могат да инвазират стената и да доведат до септикопиемия </li><li>Най-често водят до хипохлорхидрия </li><li>Инфекцията с Helicobacter pylori предшества развитието на пернициозна анемия </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>131.</strong> 42-годишен мъж е с малабсорбтивен синдром и не обилна, без кървави примеси диария през последните няколко години. Съобщава анамнестични данни за полиартрит и инцидентни зрителни халюцинации. Компютъртомографски се установява генерализирана абдоминална лимфаденомегалия без данни за неоплазия. Ендоскопското изследване не установява езофагеални и стомашни лезии, а само широки и леко скъсени дуоденални въси. Хистологично в дуоденума се откриват множество големи, със светла цитоплазма, ПАС позитивни макрофаги в субмукозата. Коя от изброените терапевтични възможности е най-подходяща в дадения случай: </p><ul><li><strong>Антибиотици</strong></li><li>Кортикостероиди </li><li>Безглутенова диета </li><li>Сегментна дуоденална резекция </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>132.</strong> Палпирате плътен, с неравна, възлеста повърхност черен дроб на 52-годишен мъж, който е HbsAg (+). Като усложнения на заболяването му могат да се развият всички изброени по-долу състояния, с ИЗКЛЮЧЕНИЕ на: </p><ul><li><strong>Инфаркт на черния дроб</strong></li><li>Хепатоцелуларен карцином </li><li>Коагулопатия </li><li>Асцит </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>133.</strong> 59-годишна жена със застойна сърдечна недостатъчност се оплаква от засилваща се ортопнея и отоци по подбедриците. Съобщава за болки в ставите без деформации и дифузно потъмняване на кожата през последните няколко години, което не свързва с излагане на слънце. Палпира се плътен и нодулиран черен дроб. Лабораторните изследвания установяват хипергликемия, леко повишен креатинин, силно повишен серумен феритин, нормални алкална фосфатаза и билирубин и умерена хипоалбуминемия. Чернодробната биопсия показва изразена фиброза с нарушена архитектоника и обилно отлагане на желязо в хепатоцитите и Купферовите клетки без изразени възпалителни промени. Кой от изброените подходи е най-удачен: </p><ul><li><strong>Скрининг на близките роднини за установяване на сходни промени</strong></li><li>Терапия с кортикостероиди </li><li>Спиране на естрогенната терапия, която провежда </li><li>Интерферонова терапия </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>134.</strong> При компютър-томографско изследване на възрастен пациент се установява туморна маса с размери 1 см в опашката на панкреаса. Неоплазмата микроскопски наподобява на Лангерхансови острови. Коя от изброените възможности е най-вероятна: </p><ul><li><strong>Ще секретира инсулин, глюкагон или гастрин</strong></li><li>Ще доведе до развитие на карциноиден синдром </li><li>Ще нараства бързо и ще е с лоша прогноза </li><li>Често се съчетава със захарен диабет </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>135.</strong> 34-годишен мъж се оплаква от необилни, с примеси на кръв и слуз, диарийни изхождания придружени от болки в долната половина на корема. Физикалното изследване установява болезненост в долната половина на корема без туморни маси. Изследването на изпражненията установява наличие на кръв. Колоноскопията показва хиперемирана, ранима лигавица от ректума до flexura coli lienalis. При микроскопското изследване се виждат улцерации и крипт абсцеси по лигавицата. Кое от долните твърдения, касаещи заболяването, е вярно: </p><ul><li><strong>Налице е повишен риск от развитието на аденокарцином</strong></li><li>Често се усложнява с перфорация и развитие на перитонит </li><li>Налице е трансмурално възпаление </li><li>Не се съчетава със склерозиращ холангит</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>136.</strong> 44-годишен мъж е намерен в дома си в безпомощтно състояние, неориентиран и е заведен в болница. При приемането е е отбелязан иктер по кожата и лигавиците и увеличен корем с асцитна течност. Ехографското изследване установява разномерено увеличен “светещ” черен дроб. Направена е пункционна биопсия на черния дроб, която установява множество телца на Малори, левкоцитни инфилтрати, некроза на хепатоцити и изразена стеатоза. Описаната картина е характерна за: </p><ul><li><strong>Алкохолен хепатит</strong></li><li>Склерозиращ холангит </li><li>Хроничен HBV хепатит </li><li>Отравяне с парацетамол </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>137.</strong> 72-годишен мъж, без значими заболявания до момента, забелязал примес на слуз и кръв в изпражненията си. Тестът за окултни кръвоизливи е положителен. Дигиталното ректално изследване и физикалното изследване на корема не установяват патологични промени. Отбелязан е цикатрикс след апендектомия. Колоноскопоията установява стеснение на лумена на червото от циркулярна туморна формация с повърхностни разязвявания, разположена на 20 см от ануса. Кой от изброените рискови фактори е НАЙ-ВЕРОЯТЕН за развитието на лезията: </p><ul><li><strong>Богата на мазнини диета</strong></li><li>Болест на Крон </li><li>Дивертикулоза </li><li>Предшестваща хирургична намеса </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>138.</strong> Касае се за 3 месечно дете от мъжки пол, родено доносено, без малформации. Майката забелязва подуване на корема и разреждане на изхожданията през последните 2-3 седмици. При физикалното изследване се установява леко уголемен, неболезнен корем. Рентгенографското изследване установява силно дилатиран колон. Коя от изброените патологични находки и НАЙ-ВЕРОЯТНА: </p><ul><li><strong>Аганглионерен сегмент на колона</strong></li><li>Волвулус </li><li>Инвагинация </li><li>Мекониум илеус </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>139.</strong> 49-годишен мъж забелязал увеличаване на корема си. При физикалното изследване коремът е неболезен, но се установява наличие на течност. Направена е абдоминоцентеза и е източена 2000 мл бледожълта течност, бедна на белтъчно съдържание. Цитологичното изследване на асцитната течност установява сравнително беден на клетки материал, представен от мезотелни клетки, макрофаги и само единични лимфоцити. Кое от изброените състояния НАЙ-ВЕРОЯТНО е налице при пациента: </p><ul><li><strong>Микронодуларна цироза</strong></li><li>Перфорирала стомашна язва </li><li>Остър панкреатит </li><li>Болест на Крон </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>140.</strong> При кое от изброените състояния е НАЙ-МАЛКО ВЕРОЯТНО да се развие исхемия, последвана от инфаркт на тънкото черво: </p><ul><li><strong>Терминален илеит</strong></li><li>Волвулус </li><li>Инкарцерирана херния </li><li>Тромбоза на горна мезентериална артерия </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>141.</strong> Всички от изброените находки могат да са резултат от портална хипертония при цироза С ИЗКЛЮЧЕНИЕ на: </p><ul><li><strong>Васкулит</strong></li><li>Хемороиди </li><li>Асцит </li><li>Спленомегалия </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>142.</strong> 25-годишен мъж се оплаква от подуване на корема и диария. Често боледува от пневмонии като е изолирван Pseudomonas aeruginosa. Установяват се повишени хлориди при потен тест и повишено съдържание на липиди в изпражненията. Коя от изброените находки НАЙ-ВЕРОЯТНО е налице: </p><ul><li><strong>Ацинарна атрофия на панкреаса</strong></li><li>Мекониум илеус </li><li>Атеросклероза на мезентериалните артерии </li><li>Синдром на Цьолингер-Елисън </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>143.</strong> 33-годишен мъж се оплаква от пареща болка зад гръдната кост след нахранване. Не съобщава за гадене и повръщане. Тестът за окултни кръвоизливи е отрицателен. Еконоскопското изследване установява хиперемия на лигавицата в долната трета на хранопровода. Щипковата биопсия от тези участъци показва неутрофилна инфилтрация и елонгация на папили. Тези промени съответстват на: </p><ul><li><strong>Лек рефлуксен езофагит</strong></li><li>Баретов езофаг </li><li>Склеродерма </li><li>Herpes simplex вирусен езофагит </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>144.</strong> Кое от изброените сътояния е НАЙ-МАЛКО ВЕРОЯТНО да даде положителен тест за окултни кръвоизливи: </p><ul><li><strong>Остър апендицит</strong></li><li>Дивертикулоза на сигмата </li><li>Аденоматозен полип </li><li>Псевдомемранозен колит </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>145.</strong> 45-годишна жена се оплаква от засилващ се сърбеж през последните три месеца. Чернодробната биопсия показва деструкция на интрахепатални жлъчни каналчета, лимфоплазмоцитоидна инфилтрация в порталните трактове с нарушаване на граничната ламела. Кое от изброените заболявания съответства на описаната картина: </p><ul><li><strong>Първична билиарна цироза</strong></li><li>Панкреатичен аденокарцином </li><li>Хроничен алкохолизъм </li><li>Застойна сърдечна недостатъчност</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>146.</strong> Кое от долните твърдения, касаещи карцинома на жлъчния мехур и екстрахепаталните жлъчни пътища е НЕПРАВИЛНО: </p><ul><li><strong>5-годишната преживяемост е повече от 90%</strong></li><li>Има повишен риск от развитие на карцином при болните със склерозиращ холангит </li><li>При повечето от болните с карциноми на жлъчния мехур се откриват конкременти на жлъчния мехур </li><li>Хистологично, повечето от тези карциноми са аденокарциноми </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>147.</strong> Мъж на средна възраст без съпътстващи и предходни заболявания се оплаква от увеличаваща се болка в гърба и дясното бедро през последните десет години. Болката била по-силна в края на деня. Налице са увеличени интерфалангеални стави с костна плътност. На спинална рентгенография се откриват проминиращи остеофити, засягащи телата на прешлените. Установена е също склероза със стесняване на ацетабулното ставно пространство. Кой е най-вероятният патологичен процес: </p><ul><li><strong>Остеоартрит</strong></li><li>Подагра </li><li>Ревматоиден артрит </li><li>Лаймска болест </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>148.</strong> От няколко месеца 51-годишен мъж се оплаква от болка в дясното бедро. На рентгенографията се открива маса с размери 10 на 13 см. Морфологично туморът е с неравни граници, светлосин на срез и има участъци на изразена костна деструкция, както и пръснати калцификати. Кое е най-правилното твърдение за тази лезия: </p><ul><li><strong>Понякога произлиза от доброкачествени хрущялни тумори</strong></li><li>Най-честият първичен костен тумор </li><li>Обикновено се среща в дисталните кости </li><li>По-често е при жени </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>149.</strong> 13-годишно момче се оплаква от персистираща от няколко седмици болка в левия крак. Момчето има също субфебрилитет. На рентгенографията се открива маса в диафизалната област на левия фемур с надлежаща кортикална ерозия и мекотъканна екстензия. Направена е биопсия и микроскопски е установено, че лезията се състои от многобройни малки сини клетки. Най-вероятната диагноза е: </p><ul><li><strong>Сарком на Ewing</strong></li><li>Медулобластом </li><li>Невробластом </li><li>Хондробластом </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>150.</strong> От един месец, след всяка тренировка по футбол, 16-годишен младеж изпитва болка в лявото коляно. На рентгенографията се открива маса, произхождаща от проксималната метафиза на тибията, която ерозира костния кортекс и повдига периостеума, където се вижда реактивно формирана нова костна тъкан. Масата не достига до епифизата. При биопсичното изследване се откриват атипични удължени клетки с хиперхромни ядра и остеоидна строма. Кое от твърденията за тази лезия НЕ Е ВЯРНО: </p><ul><li><strong>Костната травма е предразполагащ фактор</strong></li><li>Среща се по-често при мъже. </li><li>Дисталният край на фемура и тибията са чести локализации </li><li>Метастазите са обикновено хематогенни </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>151.</strong> 53-годишен мъж има бавно нарастваща “подутина” на рамото. Туморната маса е ексцизирана и при огледа срезната и повърхност е белезникава и с мековата консистенция. Микроскопски се състои от издължени игловидни кристали, които са заобиколени от грануломатозен възпалителен инфилтрат. Кое от следващите твърдения за описаното заболяване НЕ Е ВЯРНО: </p><ul><li><strong>Повечето пациенти с хиперурикемия го развиват</strong></li><li>Често е засегната първата метатарзо-фалангеална става </li><li>Описаните кристали могат да се срещнат също в синовиалната тъкан </li><li>Тази лезия може да ерозира костта и хрущяла </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>152.</strong> От години 75-годишен мъж се оплаква от болка в кръста. С оглед изясняване на открита лимфоцитоза на този мъж е направена трепанобиопсия от илиачната кост. Хематопоезата е нормална, но костните гредички са задебелени и придават мозаечен вид на костта, налице е и повишена остеобластна и остеокластна активност. Кое от изброените състояние може да се развие като усложнение на описаното заболяване: </p><ul><li><strong>Хронична сърдечна недостатъчност</strong></li><li>Деменция </li><li>Миелофиброза </li><li>Чернодробна цироза </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>153.</strong> От няколко дни 15-годишно момче се оплаква от изразена болка и подуване в областта на лявата тазобедрена става. При пункция на ставата изтича мътен и богат на неутрофилни левкоцити аспират, но без наличие на кристали. Кое от изброените твърдения е НАЙ-МАЛКО ВЕРОЯТНО за описаното заболяване: </p><ul><li><strong>Среща се при Лаймска болест</strong></li><li>Може да е усложнение на гонорейна инфекция </li><li>Може да е усложнение на септицемия </li><li>Засягат се и малките стави </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>154.</strong> Ппоради съмнение за домашно насилие 2- годишно момче е изпратено на преглед. На рентгенографията се виждат зарастващи фрактури на дългите кости. Детето е със сини склери, увреден слух на двете уши и дисморфични зъби. Няма външни контузии и лацерации по кожата. Най-вероятното обяснение за описаните промени е: </p><ul><li><strong>Osteogenesis imperfecta</strong></li><li>Ахандроплазия </li><li>Рахит </li><li>Osteopetrosis </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>155.</strong> От няколко седмици 5-годишно момче се оплаква от болка в лявата страна на главата. На рентгенографията на черепа се вижда единична деструктивна костна лезия в областта на мастоидния израстък. Микроскопски лезията е изградена от хистиоцити, еозинофили, плазматични клетки и лимфоцити. За кое заболяване се касае най-вероятно: </p><ul><li><strong>Еозинофилен гранулом</strong></li><li>Остеоид-остеом </li><li>Osteitis fibrosa cystica </li><li>Туберкулоза</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>156.</strong> 49-годишна жена забелязва, че не може да разгъва докрай средния пръст на дясната си ръка. В основата на пръста има неправилна маса, много твърда при палпация. Какъв е най-вероятния хистологичен вид на тази маса: </p><ul><li><strong>Фиброматоза</strong></li><li>Грануломатозно възпаление </li><li>Дистрофична калцификация </li><li>Гигантоклетъчен тумор на сухожилието. </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>157.</strong> Късно вечерта 58-годишен мъж получава внезапен пристъп на остра болка в големия пръст на крака. Няма анамнестични данни за травма. Болката е съпроводена от оток и зачервяване, но без кожни улцерации. Ставният аспират е богат на неутрофили. През следващите няколко седмици мъжът получава още два подобни епизода. При прегледа между пристъпите има минимално ограничение на ставната подвижност. Кой от изброените лабораторни резултати е най-показателен за описаното заболяване: </p><ul><li><strong>Хиперурикемия</strong></li><li>Хипергликемия </li><li>Положителни антинуклеарни антитела </li><li>Хиперкациемия </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>158.</strong> Поради тежък системен лупус еритематодес с бъбречно засягане 38-годишна жена е лекувана продължително с кортикостероиди. Кое от изброените костни заболявания е най-вероятното усложнение на приложената терапия: </p><ul><li><strong>Остеопороза</strong></li><li>Болест на Paget </li><li>Рахит </li><li>Остеомалация </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>159.</strong> След продължително седене в тясно помещение 23-годишен мъж изпива лек дискомфорт в латералната част на дясното коляно. В болезнената област се палпира ограничена “подутина”. На рентгенография се вижда латерално изпъкваща формация от метафизната част на фемура. Няма оток на надлежащите меки тъкани. Туморът е ексцизиран и се установява, че е съставен от костно вещество, покрито с хрущялна тъкан. Тази лезия най-вероятно е: </p><ul><li><strong>Остеохондром</strong></li><li>Гигантоклетъчен тумор </li><li>Енхондром </li><li>Остеоид-остеом </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>160.</strong> От няколко години 45-годишен мъж се оплаква от болка в дясното коляно. Няма оток на ставата. При движение през деня болката отслабва. Подлежащото заболяване вероятно е: </p><ul><li><strong>Остеоартрит</strong></li><li>Остеопороза </li><li>Остеохондром </li><li>Остеомалация </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>161.</strong> Жена на 30 години има две здрави деца. От шест месеца няма менструация, но не е вземала лекарства и тестът за бременност е негативен. От няколко месеца има главоболие, а през последната седмица забелязала млекоподобна секреция от гърдите си. Едва не блъска колата си в автобус, докато се престроявала в друга лента за движение. При преглед офталмолог установява ограничено периферно зрение. Изследванията ще покажат най-вероятно: </p><ul><li><strong>Хиперпролактинемия</strong></li><li>Увеличен серумен кортизол </li><li>Увеличени нива на соматотропен хормон </li><li>Хипонатремия </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>162.</strong> Жена на 28 години от седмици не може да се концентрира върху работата си и постоянно се разхожда и стои при колегите си. Оплаква се, че в помещенията е много горещо. Изглежда нервна и често си разлива кафето. Храни се повече, но е отслабнала с 5 kg за последния месец. Кое от следните лабораторни изследвания е най-подходящо: </p><ul><li><strong>Увеличен тироксин</strong></li><li>Намален плазмен инсулин </li><li>Увеличен ACTH </li><li>Увеличен калцитонин </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>163.</strong> Жена на 29 години с първа бременност не е посещавала женска консултация. Преди раждането се установява placenta praevia. Раждането на доносено дете е съпроводено с масивна кръвозагуба и шок. След раждането жената не е в състояние да кърми, не се възстановява менструалният й цикъл, чувства се бавна и изморена. Рентгеновото изследване на гръдния кош не открива патологични промени. Лабораторните изследвания показват хипонатремия, хипокалемия и хипогликемия. Тези данни са най-характерни за: </p><ul><li><strong>Некроза в хипофизата</strong> (Синдром на Шийхан)</li><li>Двустранни надбъбречни кръвоизливи </li><li>Тиреоидит </li><li>Метастази от хориокарцином </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>164.</strong> Касае се за жена на 49 г., която за период около 2 години наддала 5 kg, чувствала се отпусната и не понасяла студ. Физикалното изследване не открива нищо. Щитовидната й жлеза не е уголемена. Серумното ниво на TSH е 11.7 mU/L с thyroxine 2.1 micrograms/dL. В миналото е имала повишени титри на антитироглобулинови и антимикрозомиални антитела. Тези находки са най-честите белези на: </p><ul><li><strong>Тиреоидит на Hashimoto</strong></li><li>Тиреоидит на DeQuervain </li><li>Папиларен микрокарцином </li><li>Болест на Grave </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>165.</strong> Кой от следните патологични процеси е НАЙ-МАЛКО вероятен при лабораторни данни за хипертиреоидизъм: </p><ul><li><strong>Медуларен карцином на щитовидната жлеза.</strong></li><li>Фоликуларен аденом на щитовидната жлеза. </li><li>Нодозна струма </li><li>Тиреоидит на Hashimoto</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>166.</strong> Жена на 47 години опипала \"бучка\" в шията си, която не е забелязала преди няколко месеца. При преглед лекар описва плътен възел в щитовидната жлеза с размери около 2 cm в ляво от срединната линия. Сцинтиграфията с Tc99 показва, че възелът е \"студен\" при запазена активност на околния паренхим. Тези находки насочват най-вероятно към: </p><ul><li><strong>Фоликуларен аденом</strong></li><li>Грануломатозен тиреоидит </li><li>Киста на ductus thyroglossus </li><li>Нодозна струма </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>167.</strong> Поради коремна болка на жена на 55 години е направен абдоминален CT скенер. Единствената находка е туморна формация в дясната надбъбречна жлеза с диаметър 3 cm. Туморът е отстранен оперативно и биопсичното изследвана показва клетки, наподобяващи тези от надбъбречната кора. Кой от изброените е най-сигурният белег за малигненост: </p><ul><li><strong>Метастази</strong></li><li>Клетъчен атипизъм </li><li>Наличие на митози </li><li>Размер </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>168.</strong> При тънкоигленна аспирационна биопсия от \"бучка\" в шията на 47 годишна жена се установяват цитологични данни за малигнен процес в щитовидната жлеза. Поради това е направена тиреоидектомия. В долния полюс на десния лоб се намира формация с диаметър 3 cm, на срез кистична, с папиларни разраствания. Коя от следните групи хистологични находки е най-типична за тази лезия: </p><ul><li><strong>Клетки със светли (матово-стъкловидни) ядра.</strong></li><li>Фоликуларни структури, с или без колоид, тапицирани с тъмни клетки с полиморфни ядра. </li><li>Амилоидна строма между гнезда и повлекла от туморни клетки. </li><li>Капсулиран възел с белези за морфо-функционална активност. </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>169.</strong> Коя от следните ендокринни неоплазми има най-добра прогноза: </p><ul><li><strong>Папиларен карцином на щитовидната жлеза</strong></li><li>Фоликуларен карцином на щитовидната жлеза </li><li>Анапластичен карцином на щитовидната жлеза </li><li>Карцином на паращитовидната жлеза </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>170.</strong> Жена на 40 години забелязала неболезнено подуване в предната част на шията в зоната на щитовидната жлеза. Има увеличени титри на антимикрозомални и антитиреоглобулинови антитела. След месец подуването намаляло. Всички от изброените твърдения са верни ОСВЕН: </p><ul><li><strong>Хистологично се установява амилоид</strong></li><li>При това заболяване има увеличен риск от лимфом. </li><li>Хистологично се намират лимфни фоликули </li><li>Установява се генетичен дефицит на антиген специфични Т лимфоцити </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>171.</strong> Жена на 45 години с тежък ревматоиден артрит е на хронична кортикостероидна терапия от 15 години. Хоспитализирана е в Ортопедична клиника за корекция на ставна деформация и приема обичайната си доза от 5 mg prednisone на ден. На третия ден след операцията развива пневмония с изолирана Klebsiella pneumoniae от храчка, а след още два дена – станала объркана. Лабораторните изследвания на кръвта показват: натрий 105 mmol/L, калий 5.4 mmol/L, хлориди 87 mmol/L, CO2 16 mmol/L, захар 2,2 mmol/L и креатинин 1.1 mg/dL. Кое от следните състояния обяснява най-добре тези находки: </p><ul><li><strong>Остра Адисонова криза</strong></li><li>Остра некроза в предния дял на хипофизата (синдром на Sheehan) </li><li>Синдром на Waterhouse-Friderichsen </li><li>Синдром на Conn </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>172.</strong> Мъж на 41 години пие големи количества вода – до 20 литра на ден. Лабораторните му показатели са: натрий 162 mmol/L, калий 4.1 mmol/L, хлориди 121 mmol/L и бикарбонати 27 mmol/L; кръвна захар 4,1 mmol/L , креатинин 1.2 mg/dL, серумен осмоларитет 343 mOsm/kg. Това състояние е резултат от недостиг на: </p><ul><li><strong>Антидиуретичен хормон (ADH)</strong></li><li>Окситоцин </li><li>Инсулин </li><li>Prolactin </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>173.</strong> От изброените състояния едно е НАЙ-МАЛКО вероятната етиология на хронична кортикална недостатъчност на надбъбречните жлези: </p><ul><li><strong>Травматично увреждане</strong></li><li>Метастатичен карцином </li><li>Туберкулоза </li><li>Амилоидоза </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>174.</strong> Момиче на 17 години страда от синдрома на Goodpasture. Заболяването е довело до хронична бъбречна недостатъчност и хронична хемодиализа. Развива и високостепенна артериална хипертония. Момичето не оценява сериозността на заболяването си и не сътрудничи в лечението – пропуска хемодиализи и не взема медикаменти за хипертонията. Серумнит йонизиран калций е 3.9 mg/dl, фосфорът 6.2 mg/dl и албумините 3.6 g/dl. Умира от сърдечна недостатъчност. Кои са най-вероятните промени в костите, установени при аутопсията: </p><ul><li><strong>Osteitis fibrosa cystica</strong></li><li>Фиброзна дисплазия </li><li>Osteosarcoma </li><li>Остеопетроза </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>175.</strong> На профилактична мамография на 47-годишна жена се откриват множество малки зони с повишена плътност. Не се установява мамографски или палпаторно добре отграничен възел. Направена е ТАБ от подозрителния участък - интерпретирана като съдържаща \"клетки, подозрителни за малигнени\". Последваща ексцизионна биопсия - лобуларен карцином in situ. Кое от изброените твърдения е най-вероятно: </p><ul><li><strong>Другата гърда също може да бъде засегната</strong></li><li>Неоплазмата ще остане локализирана </li><li>Липсва фамилна история за карцином на гърдата </li><li>Изследването на естрогенните рецептори ще е негативно</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>176.</strong> 20-годишна жена опипва \"възел\" на лявата гърда и посещава личния си лекар. Той палпира гърдата и установява, че образуванието е плътно, добре отграничено и подвижно, с размери около 1,5/2 см. Няма секреция от зърното и болка. Не се палпират увеличени аксиларни лимфни възли. Уринният тест за бременност е негативен. Мамографското изследване потвърждава наличието на окръглен участък с повишена плътност, без микрокарцификати в лявата гърда и липса на промени в дясната. Коя от изброените лезии е най-вероятна: </p><ul><li><strong>Фиброаденом</strong></li><li>Огнищна мастна некроза </li><li>Интрадуктален папилом </li><li>Инфилтративен дуктален карцином </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>177.</strong> 19-годишна жена кърми от 1 месец здраво роденото си дете. От 3-4 дни се появил оток и болезненост при докосване в лявата гърда. Няма фебрилитет. Кое от изброените състояния е най-вероятно: </p><ul><li><strong>Остър мастит</strong></li><li>Фиброкистична болест </li><li>Мастна некроза </li><li>Интрадуктален папилом </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>178.</strong> 35-годишна жена има плътна, палпируема маса с неправилни очертания в дясната гърда. На прегледа не се установяват болезненост и перифокален оток. Мамографското изследване показва 2 см плътен участък с пръснати микрокалцификати. Биопсичното изследване установява изразена мастна некроза. Най-вероятната етиология е: </p><ul><li><strong>Травма</strong></li><li>Бременност </li><li>Пролактином </li><li>Фиброкистична болест </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>179.</strong> 29-годишна жена приема орални контрацептиви от many години. Палпира \"възел\" в лявата си гърда. Кое от изброените заболявания най-вероятно е свързано с приема на контрацертиви: </p><ul><li><strong>Галактоцеле</strong></li><li>Остър мастит </li><li>Мастна некроза </li><li>Формиране на киста </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>180.</strong> Дясната гърда на 49-годишна жена постепенно увеличава обема си. Липсва болезненост, но големият й обем и тежест предизвикват известен дискомфорт. Кожата на гърдата и ареолата са непроменени. Няма изтичане на секрет от зърното. Липсва аксиларна лимфаденомегалия. Мамографията показва 12 см окръглена маса. Направена е биопсия и микроскопското изследване установява наред с епителната компонента и изразена целуларна стромна компонента. Лезията най-вероятно представлява: </p><ul><li><strong>Филоиден тумор</strong></li><li>Фиброаденом </li><li>Склерозираща аденоза </li><li>Медуларен карцином. </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>181.</strong> 55-годишна жена напипва \"бучка\" в дясната си гърда. Лезията е неподвижна и доста плътна. Направена е ТАБ, която установява туморни клетки (карцином). Кой от изброените признаци е с лошо прогностично значение: </p><ul><li><strong>Туморни клетки в аксиланите лимфни възли</strong></li><li>Туморните клетки са позитивни за естрогенни рецептори </li><li>Фамилна анамнеза за карцином на гърдата </li><li>Наличието на in situ компонента </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>182.</strong> 45-годишна жена опипва \"възел\" на лявата си гърда. Направена е биопсия. Коя от изброените патологични промени прави развитието на последващ карцином много вероятно: </p><ul><li><strong>Лобуларна епителна хиперплазия</strong></li><li>Склерозираща аденоза </li><li>Мастна некроза </li><li>Множество кисти </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>183.</strong> Скоро след раждане, под зърното на лявата гърда на 20-годишна жена се появява болезнена подутина с диаметър 3см. Зърното е с няколко болезнени фисури. Кое от изброените патологични състояния е най-вероятно: </p><ul><li><strong>Стафилококус ауреус инфекция</strong></li><li>Инфилтративен дуктален карцином </li><li>Множество плазматични клетки </li><li>Склерозираща аденоза </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>184.</strong> При самоизследване 25-годишна жена опипва \"възел\" в лявата си гърда. Направена е ТАБ, която не установява туморни клетки, но лезията персистира. Направена е биопсия и се диагностицира фиброкистична болест. Всички изброени хистологични промени могат да бъдат налице, с изключение на: </p><ul><li><strong>Хрущялна метаплазия</strong></li><li>Апокринна метаплазия </li><li>Дуктална епителна хиперплазия </li><li>Фиброза </li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>185.</strong> 39-годишна жена съобщава, че от няколко месеца има възпаление на кожата на дясната гърда. При прегледа се установява екзематозен участък на кожата на ареолата с диаметър около 1 см. Не се палпира туморна маса в паренхима на гърдата. Биопсичното изследване установява големи атипични клетки в областта на епидермиса. Клетките съдържат муцин, което се установява с ПАС реакция. Най-вероятната диагноза е: </p><ul><li><strong>Болест на Пейджет</strong></li><li>Папилом на голям изходящ канал </li><li>Интрадуктален карцином </li><li>„Инфламаторен” карцином</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>186.</strong> 31-годишна жена забелязала отделяне на кървав секрет от дясната гърда. При прегледа не се установява палпируема маса или болезненост в гърдата. Кожата на гърдата е без промени. Тази находка говори най-вероятно за:</p><ul><li><strong>Интрадуктален папилом</strong></li><li>Мастит</li><li>Травма</li><li>Инфилтративен дуктален карцином</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>187.</strong> При жени в репродуктивната възраст повечето палпируеми лезии, които се изследват морфологично, се оказват:</p><ul><li><strong>Фиброкистична болест</strong></li><li>Абсцеси</li><li>Фиброаденоми</li><li>Интрадуктален карцином</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>188.</strong> Коя от изброените находки предполага по-добра прогноза при 45-годишна жена с карцином на гърдата:</p><ul><li><strong>Интрадуктален (in situ) растеж</strong></li><li>Нисък процент на туморни клетки с естрогенни рецептори</li><li>Единична метастаза в аксиларен лимфен възел</li><li>Анеуплоидия на туморните клетки</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>189.</strong> При коя от изброените пациентки е най-вероятно физикалното изследване да установи солитарен, плътен, добре отграничен възел в долния външен квадрант на млечната жлеза:</p><ul><li><strong>22-годишна жена без субективни оплаквания</strong></li><li>62-годишна жена с увеличен и плътен аксиларен лимфен възел</li><li>5-годишно момиче с белези за преждевременен пубертет</li><li>45-годишна жена с кървав секрет от мамилата</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>190.</strong> Мъж на 25 години кара скейтборд и удря лявата страна на главата си в бетонна стена. Получава охлузване и минимално кървене, което спира за няколко минути. След инцидента е в добро състояние, но след около 30 минути губи съзнание. Изследването с компютър томограф в болницата показва изпъкнала, лещовидна зона на кръвоизлив, ограничена в лявата париетална зона. Кои от вътречерепните кръвоносни съдове са най-вероятно увредени:</p><ul><li><strong>Средна менингеална артерия</strong></li><li>Мостови вени</li><li>Трифуркация на средната церебрална артерия</li><li>Голямата вена на Galen</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>191.</strong> Мъж на 70 години се оплаква от прогресиращо главоболие от два дена. Установява се вратна ригидност; фебрилитет 38.7 C, пулс 85, дихателна честота 23, кръвно налягане 130/85 mm Hg. Лабораторните изследвания на кръвта показват: левкоцити 16850/microliter; серумни електролити - натрий 145 mmol/L, калий 4.3 mmol/L, хлориди 103 mmol/L и кръвна захар 88 mg/dL. Лумбалната пункция установява мътен ликвор с глюкоза 32 mg/dL, белтъци 146 mg/dL и клетки 3800 левкоцити (95% полиморфонуклеари и 5 % мононуклеари) и 122 еритроцити. Това състояние може да доведе (рано или късно) до следните усложнения ОСВЕН:</p><ul><li><strong>Субдурален хематом</strong></li><li>Хидроцефалия</li><li>Тромбоза и инфаркт</li><li>Малкомозъчно тонзиларно вклиняване</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>192.</strong> Жена на 68 години е оставена за обгрижване в Дом за стари хора, понеже непрекъснато излиза от къщи и се губи в квартала, не може да поддържа ред в стаята си и се облича странно. Тези проблеми са възникнали постепенно и се влошават за последните шест години. Работила е като счетоводител, но се пенсионира преждевременно, защото започва често да греши. Няма данни за травма или гърчове. Коя от хистологичните находки е най-вероятна в този случай:</p><ul><li><strong>Неврофибрилярни сплетения и сенилни плаки</strong></li><li>Атрофия на нуклеус каудатус и глиоза</li><li>Депигментация на Substantia nigra и загуба на неврони</li><li>Групирана атрофия на скелетни мускули загуба на неврони в предните рога на гръбначния мозък</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>193.</strong> По време на радикална простатектомия на 73-годишен мъж без хронични заболявания, анестезиологът съобщава за спадане на кръвното налягане. Хипотензията продължава 30 минути, въпреки приложените пресорни медикаменти. Най-вероятното усложнение на този продължителен хипотензивен инцидент е:</p><ul><li><strong>Линеарен парасагитален инфаркт</strong></li><li>Лакунарни инфаркти на базалните ганглии</li><li>Хеморагичен инфаркт в париеталния лоб</li><li>Некроза на аденохипофизата</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>194.</strong> 28-годишен мъж е подложен на химиотерапия поради остра миелогенна левкемия. Лабораторните изследвания показват тежка панцитопения с левкоцити 1320/microliter, Hgb 7.9 g/dL и тромбоцити 72,000/microliter. Изпада в кома. Компютър-томографското сканиране показва кръвоизлив вдясно париетално. Аутопсията установява тромбоза на дясната средна мозъчна артерия и хеморагичен инфаркт вдясно париетално. Кой от изброените инфекциозни агенти причинява такива находки:</p><ul><li><strong>Aspergillus niger</strong></li><li>Herpes simplex virus</li><li>Toxoplasma gondii</li><li>Human immunodeficiency virus</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>195.</strong> Преждевременно родено бебе в 29 гестационна седмица. Майката не е имала проблеми по време на бременността, но е продължила да пуши по една кутия цигари дневно. След раждането бебето е подложено на сърфактантна терапия и не е развило респираторен дистрес от хиалинно-мембранна болест. Обаче, на втория ден получава гърч. Коя от следните лезии може да обясни това усложнение:</p><ul><li><strong>Интравентрикулен кръвоизлив</strong></li><li>Интрацеребeларен кръвоизлив</li><li>Субгалеален кръвоизлив (Caput succedaneum)</li><li>Епидурален кръвоизлив</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>196.</strong> При тежка травма на главата след катастрофа с мотоциклет 18-годишна жена е в децеребрация. При преглед на очните дъна се установява изразен двустранен оток на папилите. Компютъртомографското сканиране показва дифузен мозъчен оток. Увеличаването на обема на мозъчното вещество, поради задръжка на натрий и вода е най изразено в:</p><ul><li><strong>Бялото вещество</strong></li><li>Телата на невроните</li><li>Лептоменингите</li><li>Епендима</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>197.</strong> Жена на 31-години забелязала, че и е трудно да контролира движението на ръцете си, да пише и почеркът и станал нечетлив. При неврологичен преглед се установява намалена сила на дясната ръка и намалена сетивност на левия крак. Не се отбелязват данни за гърч или психични отклонения. Лумбалната пункция установява увеличени нива на IgG и мононуклеарни клетки в ликвора. Коя от изброените патологични находки най добре отговаря на състоянието:</p><ul><li><strong>Периваскуларни лимфоцити и демиелинизирани аксони в бялото вещество</strong></li><li>Загуба на пигментирани неврони в substantia nigra</li><li>Наличие на неврофибрилярни сплетения и невритни плаки в кората</li><li>Огнища от многоядрени клетки и макрофаги в сивото и бялото вещество</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>198.</strong> При 50-годишен мъж е с регистрирано кръвно налягане 182/108 mm Hg през последното си посещение при общо-практикуващ лекар. Отказва да приема каквито и да е медикаменти. Шест месеца по-късно е хоспитализиран поради внезапно настъпила загуба на съзнание. Когато идва в съзнание, не може да говори и да движи десните си крайници. Той вероятно има:</p><ul><li><strong>Кръвоизлив в putamen</strong></li><li>Субфронтален менингиом</li><li>Церебрална венозна тромбоза</li><li>Болест на Alzheimer</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>199.</strong> Мъж на 52 години страда от хроничен алкохолизъм. Хоспитализиран е след травма, при която пада назад и удря тила си. Компютър-томографското сканиране не установява вътречерепен кръвоизлив. Ядрено-магнитният резонанс показва атрофия на предната част на vermis на малкия мозък. Коя от следните находки е най-вероятна при физикалното изследване:</p><ul><li><strong>Атаксия</strong></li><li>Хореиформени движения</li><li>Нистагъм</li><li>Тремор при покой, който намалява при движение</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>200.</strong> Жена на 31 години, без оплаквания, внезапно губи съзнание и е отведена в болница. Спешно компютър-томографско сканиране показва масивен субарахноидален кръвоизлив по мозъчната основа. Жената е афебрилна. Лумбалната пункция установява множество еритроцити без левкоцити, леко увеличени протеини и нормални захари в ликвора. Кое от следните състояния подозирате при тази пациентка:</p><ul><li><strong>Руптура на вродена аневризма</strong></li><li>Остър бактериален менингит</li><li>Прогресивен мултифокален левкоенцефалит</li><li>Болест на Tay-Sachs</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>201.</strong> Няколко от членовете на голямо семейство се оплакват от намаляване на паметта, нарушена координация на движенията, като достигнат до средна възраст. Движенията им се определят като хореоатетоза. Генетичните изследвания показват увеличено повтаряне на тринуклеотид CAG. Коя от следните структури ще бъде макроскопски променена при аутопсията:</p><ul><li><strong>Nucleus caudatus</strong></li><li>Мозъчен ствол</li><li>Темпорален лоб</li><li>Ганглии на дорзалното коренче</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>202.</strong> Мъж на 22 години е претърпял травма на предмишницата, в резултат на която е настъпила трансверзална резекция на Nervus medianus. След тази травма нервът ще претърпи:</p><ul><li><strong>Валерова дегенерация</strong></li><li>Фибриноидна некроза</li><li>Коагулативна некроза</li><li>Сегментна демиелинизация</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>203.</strong> Разширяване на страничните вентрикули на главния мозък от обструкция на пътищата за циркулация на ликвор е НАЙ-МАЛКО вероятната етиология при:</p><ul><li><strong>Предшестващ менингит, причинен от Pneumococcus</strong></li><li>Раздвоен Силвиев акведукт</li><li>Епендимом</li><li>Интравентрикулен кръвоизлив</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>204.</strong> Жена на 41 години е от една седмица с прогресиращо главоболие, унесеност и висока температура. Скенерът установява единична, окръглена лезия с диаметър 3 cm с пръстеновидна интензивност, разположена в десния паритален лоб. Направена е стереотактична биопсия. Гефрирното изследване показва гранулационна тъкан с колагенизация, глиоза и оток в съседство. Вероятната причина за тези находки е:</p><ul><li><strong>Хроничен мозъчен абсцес</strong></li><li>Аспергилоза</li><li>Токсоплазмоза</li><li>Бяс</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>205.</strong> Мъж на 66 години се оплаква, че му е трудно да върви. Изпитва досадно треперене на ръцете, което изчезва, ако върши нещо рутинно. Приятелите му забелязали, че изглежда по-тъжен, рядко се усмихва и гледа втренчено. Няма нарушения в мисловната дейност. Коя е вероятната болест:</p><ul><li><strong>Болест на Parkinson</strong></li><li>Амиотрофична латерална склероза (ALS)</li><li>Болест на Alzheimer.</li><li>Болест на Niemann-Pick</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>206.</strong> Жена на 72 години от пет години е с влошаваща се умствена дейност и има проблеми с паметта. Няма двигателни нарушения. При ядрено-магнитен резонанс сканиране на мозъка се установява симетрично увеличение на страничните вентрикули и атрофия на кората на големите полукълба, предимно във фронталната и париеталната зона. Лумбалната пункция установява бистър ликвор, под нормално налягане и лабораторни показатели – протеин и глюкоза нормални граници, левкоцити - 3 (всички лимфоцити) и еритроцити – 1. Очни дъна – без промени. Коя от изброените находки е характерна за заболяването й:</p><ul><li><strong>Наличие на eпсилон 4 алел на аполипопротеин E</strong></li><li>Загуба на GABA (gamma aminobutyric acid)</li><li>Увеличен брой телца на Lewy</li><li>Загуба на клетки на Betz</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>207.</strong> Жена на 26 години, досега здрава, внезапно станала объркана, получила гърч и е заведена в болница. Виталните й показатели са: кръвно налягане 100/60 mm Hg, температура 37 C, пулс 89 и дихателна честота 22. Лумбалната пункция установява бистър ликвор под нормално налягане с еритроцити 1 и бели клетки 20 (всички лимфоцити). Ядреномагнитен резонанс сканирането показва оток на десния темпорален дял с хеморагични зони. Кой от следните инфекциозни агенти е вероятния причинител на тези лезии:</p><ul><li><strong>Herpes simplex virus</strong></li><li>Mycobacterium tuberculosis</li><li>Hemophilus influenzae</li><li>Neisseria meningitidis</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>208.</strong> Мъртвораждане в 28 гестационна седмица на 30-годишна майка G2 P1 (G2 = втора бременност, P1 = едно раждане), при която първата бременност е завършила с нормално раждане. При аутопсията на мъртвороденото се установява мозък с изразени дифузни зони на некроза в перивентрикулните зони. Коя от следните инфекции може да обясни находката:</p><ul><li><strong>Cytomegalovirus</strong></li><li>Taenia solium</li><li>Poliovirus</li><li>Candida</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>209.</strong> Мъж на 73 години от няколко месеца губи спомени за близки събития, които замества с конфабулации. Умира от хепатоцелуларен карцином, развил се на базата на микронодуларна цироза. При аутопсията в мозъка се намират малки мамиларни телца с кафеникава оцветка; хистологично – глиоза, съдова пролиферация и отлагане на хемосидерин. Тези находки са най-характерни за:</p><ul><li><strong>Синдром на Wernicke-Korsakoff</strong></li><li>Болест на Parkinson</li><li>Амиотрофична латерална склероза (ALS)</li><li>Болест на Huntington</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>210.</strong> Мъж на 50 години се оплаква от главоболие, станал раздразнителен и започнал да се държи странно. Един месец преди това претърпял автомобилна злополука, при която блъснал главата си в предното стъкло на автомобила си, понеже не носел предпазен колан. Имал е само подутина на челото. Не е губил съзнание в момента на инцидента, нито след това. Симптоматиката може да се обясни от наличието на:</p><ul><li><strong>Хроничен субдурален хематом</strong></li><li>Епидурален хематом</li><li>Контузионни огнища в кората на главния мозък</li><li>Интрацеребрален хематом</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>211.</strong> У здрав млад мъж, футболист, за няколко години се развива прогресираща симетрична мускулна слабост на горните крайници. След това се прибавят затруднения в говора и преглъщането. Не е имал фебрилитет, умствени нарущения, миалгия или артралгия. Най-вероятното заболяване е:</p><ul><li><strong>Амиотрофична латерална склероза (ALS)</strong></li><li>Болест на von Recklinghausen</li><li>Мултиплена склероза</li><li>Болест на Werdnig-Hoffman</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>212.</strong> Мъж на 20 години без никакви заболявания влиза в казармата. Няколко седмици след това се оплаква от целодневно главоболие, без обяснима причина, само предния ден го е заболяло гърлото. Отива на лекар, който установява: температура 39.2 C, пулс 90, дихателна честота 22 и кръвно налягане 110/70 mm Hg. По-късно е направена лумбална пункция, която показва: еритроцити 2, бели клетки 34 000, глюкоза 20 mg/dl (в серума 75 mg/dL) и протеини 105 mg/dl. Какво допълнително изследване е най-необходимо:</p><ul><li><strong>Оцветяване по Gram</strong></li><li>За криптококов антиген</li><li>За киселинно-устойчиви микроорганизми</li><li>Серология за Herpes simplex</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>213.</strong> При аутопсия на мъж на 47 години се установята: мозък с нормални размери, без атрофия и церебрални артерии без атеросклероза. На коронарните срези се виждат перивентрикулни плаки с размери от 0.3 до 1 cm. Микроскопски тези плаки показват липса на миелин при оцветяване с luxol fast blue (LFB) и запазени аксони при оцветяване с Bodian сребърна импрегнация. Това заболяване се характеризира със следните белези, ОСВЕН:</p><ul><li><strong>Връзка с Influenza virus инфекция</strong></li><li>Начало в ранна зряла възраст</li><li>Плаки на демиелинизация в бялото вещество</li><li>Протичане с пристъпи и ремисии</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>214.</strong> Мъж на 65 години има обща пареза и прогресиращи психична симптоматика. При лумбална пункция се установява позитивен VDRL тест, нормални протеини и глюкоза и само една мононуклеарна клетка. Коя от следните находки е НАЙ-МАЛКО вероятна:</p><ul><li><strong>Хеморагичен енцефалит</strong></li><li>Невронална загуба и кортикална атрофия</li><li>Ендартериит</li><li>Атрофия на задните колони на гръбначния мозък</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>215.</strong> Жена на 53 години има транзиторни исхемични атаки (TIА) от няколко години. Сега внезапно получила левостранна хемипареза. След четири месеца сканиране чрез ядрено-магнитен резонанс показва киста с площ 4 cm в дясна фронто-париетална зона. Коя от следните находки най-добре обяснява случая:</p><ul><li><strong>Оклузивна атеросклероза на коронарни артерии</strong></li><li>Хроничен менингит</li><li>Glioblastoma multiforme</li><li>Церебрален артериит</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>216.</strong> Жена съобщава на общо-практикуващия лекар, че 50-годишният й съпруг в последно време постепенно показва личностни промени, които той не осъзнава. Преди е бил енергичен, а сега става бавен и муден, започва да забравя и губи интерес към любимата си професия. MRI сканирането показва окръглена маса с диаметър 3 cm в ляво фронтално, със зони на калцификация. Коя от следните дизагнози ще бъде потвърдена хистологично:</p><ul><li><strong>Oligodendroglioma</strong></li><li>Организиращ се абсцес</li><li>Meningioma</li><li>Schwannoma</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>217.</strong> Жена на 48 години е развила хронична бъбречна недостатъчност. Скенерът установява двустранно силно уголемени бъбреци с множество кисти. Поради внезапно настъпило силно главоболие е направена мозъчна ангиография, която показва много тесен лумен на артериите по мозъчната основа, без интрацеребрален кръвоизлив. Кое от следните състояния може да обясни находките:</p><ul><li><strong>Субарахноидален кръвоизлив</strong></li><li>Бактериален менингит</li><li>Тежка атеросклероза</li><li>Малигнена хипертония</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>218.</strong> Мъж на 30 години почувствал тежест в левия си тестис. При прегледа се установява уплътнена формация в левия тестис, палпира се лимфен възел вляво ингвинално, десният тестис е нормален. Ехографията показва солидна маса с диаметър 4 cm вляво. Лабораторните находки са: хорионгонадотрофин 5 IU/L и алфа-фетопротеин 2 ng/mL. Тестисът е отстранен оперативно. Патологът описва плътна, лобулирана бледо кафява туморна формация, без кръвоизливи и некрози. Най-вероятната диагноза при хистологичното изследване е:</p><ul><li><strong>Семином</strong></li><li>Хориокарцином</li><li>Ембрионален карцином</li><li>Тумор на Teilum (тумор на жълтъчното мехурче)</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>219.</strong> При преглед на 35-годишен мъж, палпирате подутина вляво ингвинално и установявате, че в скротума липсва левия тестис, а десният е с нормални размери. Решавате, че се касае за крипторхизъм. Какво ще направите със задържания тестис:</p><ul><li><strong>Ще отстраните само него</strong></li><li>Ще завършите десцензуса на тестиса до скротума хирургично.</li><li>Ще го отстраните, заедно с другия тестис</li><li>Ще назначите терапия с тестостерон</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>220.</strong> При рутинен преглед на 70-годишен мъж без оплаквания, при ректалното туширане палпирате плътен възел в простатната жлеза. Ако биопсичното изследване на тази лезия микроскопски показва малки струпани жлези, изградени от клетки с отчетливи нуклеоли в ядрата, коя ще е вероятната диагноза:</p><ul><li><strong>Аденокарцином на простатната жлеза</strong></li><li>Бенигнена простатна хиперплазия</li><li>Хроничен простатит</li><li>Пресен инфаркт на простатната жлеза</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>221.</strong> Състояние, което предразполага към развитие на плоскоклетъчна интраепителна неоплазия на пениса у възрастен мъж, може да бъде:</p><ul><li><strong>Phimosis</strong></li><li>Herpes simplex вирусна инфекция</li><li>Balanitis xerotica obliterans</li><li>Еписпадия</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>222.</strong> Мъж на 23 години е изследван заради инфертилитет, при което се установява: нисък брой сперматозоиди, двата тестиса са разположени в скротума с нормални размери, без туморни маси; във funiculus spermaticus вляво палпаторно се усеща формация, наподобяваща “торба с червеи”. Най-вероятната диагноза е:</p><ul><li><strong>Варикоцеле</strong></li><li>Хидроцеле</li><li>Tорзия на тестса</li><li>Сперматоцеле</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>223.</strong> По време на футболен мач мъж на 72 години ходи няколко пъти да уринира в тоалетната, въпреки че е изпил само една бира. Проблемът с честото уриниране го притеснява от няколко години. При ректално туширане се установява уголемена, възловата простатна жлеза. Нивото на простата-специфичния антиген (PSA) е 5 ng/mL. Кое от следните патологични състояния ще покаже биопсията:</p><ul><li><strong>Нодуларна хиперплазия</strong></li><li>Аденокарцинома</li><li>Остро възпаление</li><li>Множествени инфаркти</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>224.</strong> Късно вечерта студент на 19 години изпитал внезапно тежък дискомфорт в скротума. Не може да си намери място. Таблетка аспирин и чаша бира не помагат. Приятел го откарал в Спешен кабинет и лекарят установил, че левият му тестис е леко уголемен и много чувствителен при палпация. Липсват увеличени ингвинални лимфни възли. Виталните показатели на студента са: температура 36 C, дихателна честота 22, пулс 80 и кръвно налягане 100/65 mm Hg. Кое от изброените състояния отговаря на описаната картина:</p><ul><li><strong>Торзия на funiculus spermaticus</strong></li><li>Varicocele</li><li>Конкремент в уретера</li><li>Hydrocele</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>225.</strong> 20 годишен студент от два дена забелязал секрет от пениса си и болки при уриниране. Микробиологично от секрета се изолира Neisseria gonorrheae. Кое от следните твърдения НЕ Е ВЯРНО:</p><ul><li><strong>Може да се развие орхит</strong></li><li>Може да се развие стриктура на уретрата</li><li>Може да се развие епидидимит</li><li>Може да не се развият усложнения</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>226.</strong> При ректално туширане на 77-годишен мъж е установена леко уплътнена възловата простатна жлеза. Серумният PSA е 5 ng/mL. Хистологичното изследване показва простатна интраепителна неоплазия (PIN). Какво ще препоръчате на този пациент:</p><ul><li><strong>Проследяване стойностите на PSA</strong></li><li>Радикална простатектомия</li><li>Химиотерапия</li><li>Трансуретрална резекция на простатата (ТУРП)</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>227.</strong> Студент на 21 години е уведомен от ХЕИ, че сексуалният му контакт преди три седмици е бил със VDRL-позитивна партньорка. Същото заболяване при него ще се прояви най-напред с:</p><ul><li><strong>Ulcus durum (chancre) на пениса</strong></li><li>Позитивен VDRL при изследване на ликвора</li><li>Луетична гума при биопсично изследване на тестиса</li><li>Еритемо-папулозен обрив по кожата и лигавиците</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>228.</strong> Мъж на 40 години забелязъл постепенно уголемяване на скротума, повече от дясната страна от около две години. Няма болка, но чувства дискомфорт. При прегледа установявате, че дясната половина на скротума е трикратно уголемена, спрямо нормалния размер на тестиса. Туморната маса при просветляване (диафаноскопия) пропуска светлина. Няма уголемени ингвинални лимфни възли. Ехографията показва тънкостенна киста с диаметър 5 cm, изпълнена с прозрачна течност. Пациентът най-вероятно страда от:</p><ul><li><strong>Hydrocele</strong></li><li>Seminoma</li><li>Торзия на тестиса</li><li>Varicocele</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>229.</strong> 30-годишен, сексуално активен мъж се оплаква от болка и парене при уриниране. Лигавицата на уретрата му е зачервена. Кой от изброените микроорганизми е най-вероятния причинител на това възпаление:</p><ul><li><strong>Chlamydia trachomatis</strong></li><li>Treponema pallidum</li><li>Вирусът на паротита</li><li>Hemophilus ducreyi</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>230.</strong> Малки бисерни папули по ръба на glans penis в здрав 17-годишен юноша представляват:</p><ul><li><strong>Доброкачествена находка без клинично значение</strong></li><li>Преканцероза</li><li>Инфекция с HPV (human papilloma virus)</li><li>Баланит, предизвикан от Staphylococcus aureus</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>231.</strong> Рутинен уринен анализ на 50-годишен дългогодишен пушач дава следните резултати: рН 5,5; относително тегло 1013, кръв 2+, липса на протеинурия и глюкозурия. При цитологичното изследване се откриват атипични уроепителни клетки. Направена е цистоскопия, която не установява мукозни лезии. С кое от следните заболявания биха се обяснили най-добре посочените резултати:</p><ul><li><strong>Преходноклетъчен карцином на бъбречното легенче</strong></li><li>Аденокарцином на простатата</li><li>Остър интерстициален нефрит</li><li>Плоскоклетъчен карцином на пениса</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>232.</strong> 35-годишна жена се оплаква от полиурия и дизурия през последните няколко дни. При физикалното изследване не се открива болка или чувствителност в областта на уретерите. Анализ на урината показва относително тегло 1014; рН 7.5; липса на протеинурия и глюкозурия; голям брой левкоцити. Серумният креатинин е 0.9 mg/dL. Кой от следващите патологични процеси е отговорен за посочените промени:</p><ul><li><strong>Остър бактериален цистит</strong></li><li>Лупусен нефрит</li><li>Уролитиаза</li><li>Преходноклетъчен карцином</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>233.</strong> 70-годишен мъж претърпява непроникваща коремна травма при падане и направената скенеграма разкрива наличието на 3 до 5 периферни малки кисти в бъбреците с диаметър 1-2 см. Серумните урея и креатинин са нормални. При анализ на урината не се откриват хематурия, кетонни тела, протеинурия или глюкозурия. Микроскопското изследване на урината открива няколко оксалатни кристали. Кое от посочените състояния е най-вероятната причина за посочените резултати:</p><ul><li><strong>Множествени обикновени кисти на бъбречната кора</strong></li><li>Бъбречна поликистоза при възрастни (доминантна форма)</li><li>Тежка атеросклероза при диабет</li><li>Рецидивиращи уроинфекции</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>234.</strong> Определението нефрозен синдром се базира на наличието на:</p><ul><li><strong>Протеинурия &gt;3.5 гр / 24 часа</strong></li><li>Липса на белези на възпаление при анализ на урината</li><li>Хематурия с &gt;10 еритроцита на зрително поле</li><li>Липидурия с хиперхолестеролемия</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>235.</strong> При рутинен анализ на урината на 12-годишно момче се открива микроскопска хематурия. Установено е, че детето страда от глухота, има корнеална дистрофия и дислокация в очната леща. Поради наличието в семейството на фамилно бъбречно заболяване, засягащо по-тежко мъжкия пол, е направена бъбречна биопсия. Микроскопски се установяват неравномерно разположени участъци на задебеляване и изтъняване на базалната мембрана на гломерулните капиляри с раздвояване на lamina densa. Мезангиалният матрикс е увеличен и епителните клетки изглеждат пенести. За кое от следващите заболявания се касае най-вероятно:</p><ul><li><strong>Синдром на Alport</strong></li><li>Синдром на Goodpasture</li><li>IgA нефропатия (болест на Berger)</li><li>Захарен диабет тип I</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>236.</strong> 45-годишна жена страда от хронична хипертония със значително увеличени нива на плазмения ренин. За една година тя развива бъбречна недостатъчност. По-късно тя преживява “удар” с дяснобазален кръвоизлив и умира. При аутопсията се намират бъбреци с намален размер и гранулирана повърхност. Микроскопски се установява хиперпластична атеросклероза с фибриноидна некроза, петехиални кръвоизливи и кортикални микроинфаркти. От кое от изброените заболявания най-вероятно е страдала тази жена:</p><ul><li><strong>Scleroderma difusum</strong></li><li>Захарен диабет тип II</li><li>Фибромускулна дисплазия</li><li>Злоупотреба с аналгетици</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>237.</strong> 3-годишно дете е станало раздразнително и загубило апетит през последните два месеца. При прегледа педиатърът открива видимо увеличен корем и палпируема маса с десностранна локализация. При КТ на коремната област се вижда солидно образувание с размери 10 см, засягащо бъбрека. При микроскопското изследване на резектираната маса се откриват малки сини клетки образуващи примитивни тубуларни структури. Детето се подлага на химио- и лъчетерапия и рецидив не настъпва. За коя от изброените неоплазми се касае най-вероятно:</p><ul><li><strong>Тумор на Wilms</strong></li><li>Бъбречноклетъчен карцином</li><li>Преходноклетъчен карцином</li><li>Медуларен фибром</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>238.</strong> 5-годишно момче е с изразено подуване около очите. Детето е с намалена активност през последната седмица. Анализът на урината дава следните резултати: относително тегло 1010; рН 6.5; значителна протеинурия; липса на кръв, отливки или кетонови тела. При микроскопско изследване на урината се откриват овални мастни тела, без наличие на еритрицити и левкоцити. Състоянието се подобрява след курс на кортикостероидно лечение. Коя от изброените бъбречни лезии е най-вероятната причина:</p><ul><li><strong>Изглаждане на подоцитните израстъци</strong></li><li>Гломерулни полулуния</li><li>Хиперпластична артериосклероза</li><li>Отлагане на имунни комплекси в мезангиума</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>239.</strong> Кое от изброените НЕ Е характерно за клиничната изява на нефритния синдром:</p><ul><li><strong>Протеинурия &gt;3.5 гр/ 24 часа</strong></li><li>Хипертония</li><li>Хематурия с еритроцитни отливки</li><li>Различна степен на олигурия</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>240.</strong> 50-годишен мъж е хоспитализиран по повод на остър инфаркт на миокарда. Той има намален ударен обем и хипотензия, изискващи прилагането на пресорни медикаменти. Диурезата намалява през следващите няколко дни. Серумната урея е силно повишена при нормални нива на креатинина. Анализът на урината показва липса на протеин или глюкоза, следи от кръв и множество хиалинни цилиндри. Няколко дни по-късно той развива полиурия и серумната урея се понижава. Коя от изброените патологични находки най-вероятно е налице в бъбреците:</p><ul><li><strong>Остра тубулна некроза</strong></li><li>Изглаждане на подоцитните израстъци.</li><li>Глумерулни полулуния</li><li>Хиперпластична артериолосклероза</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>241.</strong> При кое от следните състояние тънкоиглената бъбречна биопсия е подходяща и особено полезна:</p><ul><li><strong>Системен лупус еритематодес с остра бъбречна недостатъчност</strong></li><li>Висока температура с подозрение за остър пиелонефрит</li><li>Простатна хипертрофия с подозрение за хидронефроза</li><li>Недоносено новородено с подозрение за бъбречна поликистоза</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>242.</strong> 20-годишен мъж без предхождащи заболявания от няколко дни се чувства отпаднал. Той отива при лекаря си когато урината му става тъмно оцветена. Серумният му креатинин е повишен. Анализът на урината показва рН 6; относително тегло 1011; хематурия; лека протеинурия; множество еритроцитни цилиндри; липса на глюкозурия и кетонови тела. Коя от изброените патологични находки е вероятно да бъде открита:</p><ul><li><strong>Гломерулни полулуния</strong></li><li>Левкоцитни инфилтрати</li><li>Липидурия</li><li>IgA депозити в гломерулните капиляри</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>243.</strong> 50-годишен мъж е с диагностициран захарен диабет тип І от 15-годишен. Според изследванията на хемоглобин А1 заболяването е с лош контрол. На 35 години той е получил неоздравяваща язва на стъпалото. На 45 години този мъж е бил изложен на риск от развитие на следните компликации на диабета ОСВЕН:</p><ul><li><strong>Гломерулни полулуния</strong></li><li>Нодуларна гломерулосклероза</li><li>Артериолорна нефросклероза</li><li>Папиларна некроза</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>244.</strong> При рутинен преглед на 39-годишна жена е измерено кръвно налягане 160/105 mmНg. Жената е без субективни оплаквания и без съществени предхождащи заболявания. Анализът на урината не показва патологични отклонения. При абдоминална ехография се установява, че левият бъбрек е по-малък от десния, но в нито един от двата не са открити кисти или обемни процеси. Жената има повишен плазмен ренин. Селективната ангиография демонстрира стесняване, задебеляване и неравен релеф на лявата главна бъбречна артерия. Кое от следните състояние е най-вероятно:</p><ul><li><strong>Фибромускулна дисплазия</strong></li><li>Захарен диабет</li><li>Антифисфолипиден синдром</li><li>Тромботична тромбоцитопенична пурпура</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>245.</strong> 53-годишна жена с ревматоиден артрит е вземала 2g phenacetin дневно през последните 3 години. Жената е с повишени серумни урея и креатинин. Каква патологична находка е най-вероятно да се открие в бъбреците:</p><ul><li><strong>Папиларна некроза</strong></li><li>Фокална сегментна гломерулосклероза</li><li>Интерстициален нефрит</li><li>Артериолосклероза</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>246.</strong> 15-годишно момиче посещава личния си лекар по повод на увеличаваща се с времето отпадналост. Тя наскоро е прекарала “настинка”. Състоянието й не се подобрява след няколкоседмично лечение с кортикостероиди и се налага бъбречна биопсия. На биопсичния материал се открива сегментна склероза на 3 от 10 гломерула. При имунофлуоресцентните изследвания и електронната микроскопия не се демонстрират имунни отлагания. Какво трябва да се обясни на родителите на момичето за нейното заболяване:</p><ul><li><strong>Може да се наложи бъбречна трансплантация след 10 години.</strong></li><li>Състоянието вероятно ще се подобри след допълнителна кортикостероидна терапия.</li><li>Вероятно е да развие рестриктивно белодробно заболяване.</li><li>Има подлежащ малигнен процес</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>247.</strong> 59-годишен мъж забелязала кръв в урината си. Анализът на урината потвърждава наличието на кръв, но се открива протеинурия или глюкозурия. Урокултурата е отрицателна. Проведена е цистоскопия, при която се вижда голяма екзофитна маса в пикочния мехур. При изследване на биопсичния материал от масата се откриват фиброзносъдови повлекла, покрити с дебел слой преходни клетки. Кой от иброените рискови фактори е най-вероятно да доведе до развитие на описаната лезия:</p><ul><li><strong>Тютюнопушене</strong></li><li>Захарен диабет</li><li>Рецидивиращи уроинфекции</li><li>Терапия с метицилин</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>248.</strong> На 60-годишен мъж преди 1 година е открит аденокарцином на белия дроб и 4 сантиметровата лезия е отстранена с долна лобектомия. Сега му е направена абдоминална скенеграма, на която са открити пръснати бъбречни обемни лезии и хилусна лимфаденопатия. От няколко седмици мъжът е с увеличаваща се отпадналост. При анализа на урината се демонстрира изразена протеинурия 2,7 гр/ 24 часа. Уреята и креатининът са повишени. Направена е бъбречна биопсия и е открито фокално отлагане на IgG и C3 със зърнест характер. Най-вероятно този мъж има:</p><ul><li><strong>Мембранозен гломерулонефрит</strong></li><li>Бързопрогресиращ гломерулонефрит</li><li>Нодуларна гломерулосероза</li><li>Мембранопролиферативен ГН тип ІІ</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>249.</strong> Коя от изброените вродени аномалии носи най-голям риск за пациента:</p><ul><li><strong>Екстрофия на пикочния мехур</strong></li><li>Едностранна бъбречна агенезия</li><li>Подковообразен бъбрек</li><li>Двойни уретери двустранно</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>250.</strong> При кой от описаните случаи бъбречната папиларна некроза НЕ Е вероятно усложнение:</p><ul><li><strong>48-годишен мъж с кръвно налягане 180/100 mmHg</strong></li><li>55-годишен мъж с уроинфекция и подлежащ захарен диабет.</li><li>60-годишен мъж, който е приел големи количества аналгетици.</li><li>25-годишна бременна жена с установена бактериурия</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>251.</strong> Кое от посочените бъбречни увреждания при пациент със захарен диабет е най-вероятно да доведе до поява на левкоцити в урината:</p><ul><li><strong>Остър пиелонефрит</strong></li><li>Нодуларна гломерулосклероза</li><li>Дифузна гломерулосклероза</li><li>Артериоларна нефросклероза</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>252.</strong> При фетална ехография в 18-та гестационна седмица се установява липса на амниотична течност, затрудняваща визуализацията. Виждат се двустранно асиметрично уголемени бъбреци. Пикочен мехур не се визуализира. Сърцето изглежда четирикухинно. Краката са с варусна деформация. При раждането детето е с тежка респираторна недостатъчност. Най-вероятната диагноза е:</p><ul><li><strong>Мултикистична бъбречна дисплазия</strong></li><li>Двустранен тумор на Wilms</li><li>Доминантна бъбречна поликистоза</li><li>Уретрална атрезия</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>253.</strong> Млад, сексуално активен мъж се оплаква от пареща болка при уриниране през последните два дни. При прегледа не се откриват увреждания на пениса. При микроскопското изследване на урината се намират 50 левкоцита на зрително поле. Посявка на уретрален секрет остава негативна за Neisseria gonorrheae. Кой е най вероятния причинител:</p><ul><li><strong>Chlamydia trachomatis</strong></li><li>Human papilloma virus</li><li>Treponema pallidum</li><li>Herpes simplex virus</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>254.</strong> 59-годишен мъж се оплаква от болка в кръста през последните няколко месеца. Направен е анализ на урината като част от диференциално диагностичните изследвания. Открива се микроскопска хематурия без съпътстваща протеинурия или глюкозурия. КТ на корема демонстрира солидно образувание с размер 6 см, разположено в горния полюс на десния бъбрек. Направена е нефректомия и при микроскопското изследване на резектата се откриват клетки със светла цитоплазма, образуващи гнездни структури. Кое от посочените е НАЙ - МАЛКО ВЕРОЯТНО да съпровожда описаната лезия:</p><ul><li><strong>Хепатит</strong></li><li>Хиперкалциемия</li><li>Метастази</li><li>Полицитемия</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>255.</strong> При аутопсия на недоносено новородено, починало малко след раждането се откриват двустранно, значително увеличени бъбреци. Микроскопси бъбречният паренхим е заместен с множествени радиално подредени кисти. Тези промени най-вероятно са свързани с:</p><ul><li><strong>Съпътстващи кистозни изменения на черния дроб и фиброза на панкреаса.</strong></li><li>Автозомно доминантно заболяване.</li><li>Папилом на пикочния мехур.</li><li>Липса на развитие на уретерите.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>256.</strong> При венозна урография на 70-годишен мъж с хематурия се вижда дефект в изпълването с размер 2 см, разположен в лявото бъбречно легенче. Най-вероятно са касае за процес, който е довел също до:</p><ul><li><strong>Отделяне на атипични клетки в урината</strong></li><li>Полицитемия</li><li>Левкоцитоза</li><li>Хипертония</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>257.</strong> 10-годишно момиче посещава лекар 10 дни след прекарана ангина и при изследванията се откриват повишени урея и креатинин, микроскопска хематурия с дисморфични еритроцити. Направена е бъбречна биопсия, на която се виждат хиперцелуларитет, полиморфонуклеари и субепителни, електронно плътни отлагания, под форма на гърбици. Коя от изброените лабораторни находки може да очакваме при този случай:</p><ul><li><strong>Повишен стрептолизинов титър</strong></li><li>Повишена серумна глюкоза</li><li>Антитела срещу двойноверижната ДНК</li><li>Антитела срещу гломерулната базална мембрана</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>258.</strong> 41-годишен мъж без предшестващи заболявания се оплаква от гадене, повръщане и отпадналост през последните 4 дни. Той е забелязал, че урината му е тъмно оцветена. При физикалния преглед не се откриват патологични промени, освен кръвно налягане 135/90 mmHg. През следващия ден се покачват уреята и креатинина. При коя от изброените микроскопски находки прогнозата би била най-лоша:</p><ul><li><strong>Гломерулни полулуния.</strong></li><li>Хиперцелуларни гломерули с неутрофили</li><li>Нодуларна гломерулосклероза</li><li>Хронично интерстициално възпаление.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>259.</strong> Анализ на урината на 25-годишен мъж без субективни оплаквания дава следните резултати: относително тегло 1016; рН 6; глюкоза, кетони и нитрити - отрицателни; хематурия 3+ и протеинурия 2+. При микроскопския анализ се откриват еритроцити, но не и цилиндри. Подобни находки са откриват 6-месеца. Направена е бъбречна биопсия, която дава позитивно имунофлуоресцентно оцветяване срещу анти-IgA антитела. Какъв е вероятният изход на заболяването:</p><ul><li><strong>Бавна прогресия към хронична бъбречна недостатъчност</strong></li><li>Бърза прогресия към бъбречна недостатъчност</li><li>Повишена възприемчивост към опортюнистични инфекции</li><li>Пълно възстановяване след кортикостероидна терапия</li></ul><br><h2><strong></strong></h2>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>";
